export const meta = {
  name: 'sloe-parity-fix',
  description: 'Fix the per-surface premium-parity backlog from the sloe-parity-audit: serif typography via locked tokens, on-scale spacing, named functionality bugs, photography hooks, and web/mobile parity — one file-isolated agent per surface, web+mobile in lockstep.',
  phases: [{ title: 'Fix', detail: 'one executor per surface, fixes its full gap list' }],
}

// Per-surface gap lists inlined from the audit (c=category, s=severity 1-5, i=issue, f=fix).
const SURFACES = [{"name":"cookbook-import","model":"sonnet","impl":"apps/mobile/app/cookbook-import.tsx","gaps":[{"c":"functionality","s":5,"i":"The capture at sweep-2026-06-09/cookbook-import.png is byte-identical (md5 65661be...) to plan.png AND plan-import.png, and visually IS the Plan/Meal-plan surface, not cookbook-import. The screen is flag-gated behind cookbook_import_enabled and calls router.back() on mount when the flag is off (cookbook-import.tsx:88-92), so the harness captured the Plan fallback. _progress.log says 'OK cookbook-import' — a false positive. The screen is rendering-UNVERIFIED; all visual tiers below are code-inferred (ui-critic grade), not pixel-grounded.","f":"Re-capture with the flag forced on for the QA account: ramp cookbook_import_enabled to 100% for the test user via PostHog (global is guard-blocked), accept analytics consent, relaunch, deep-link suppr://... or navigate Recipes → + → From a PDF, then screenshot. Make the sweep harness hard-fail when a flag-gated route redirects (bundle≠HEAD / route-back guard) instead of silently saving the fallback screen under the intended name."},{"c":"typography","s":5,"i":"Recipe titles in the review list and all card titles render SANS, violating DS §2.3 rule 2 (recipe/meal names ALWAYS Fraunces). styles.cardTitle (line 359), primaryBtnText (349), segment labels (425), the 'N of M selected' line (408), and the kcal value (478) all use raw fontWeight:'700'/'600' with NO fontFamily, so they fall back to Inter/system. The only serif in the screen is the parsing/review header (Type.title) and uploadTitle (Type.headline). Every imported recipe name — the editorial content — is in the wrong typeface.","f":"Apply Type.headline/serifMedium to cardTitle and to recipe titles in the FlatList row; route the screen H1/subtitle through the serif display roles. Replace all raw fontWeight strings with Type tokens. Recipe name in the row is the single highest-impact serif fix per DS §2.3 rule 2."},{"c":"spacing","s":4,"i":"Off-scale radii throughout. uploadZone and card use borderRadius: Radius.xl * 2 = 24px (lines 336, 354); textInput and primaryBtn hardcode borderRadius:16 (327, 345); segBtn uses 14 (365). DS §4 caps card radius at radius-xl 20pt and standard cards at radius-lg 16; 24px exceeds the system's largest card radius, and 14/16 are not on the mobile Radius scale {sm4, md6, lg8, xl12, full}. The comment even rationalises 24px as 'Sloe radius' but the DS does not define a 24px token.","f":"Cards/upload zone → 16 (Radius primary-card per import.md §4 'radius 14px for large cards' or DS radius-lg 16). Inputs and buttons → 12 (radius-md). Segment buttons → 8 (radius-sm). Add a real 16/20 token rather than Radius.xl*2 arithmetic so the value is on-scale and auditable."},{"c":"spacing","s":3,"i":"Several paddings/margins are off the Spacing grid {4,8,16,20,24,32,40}. textInput padding:14 (328) and uploadHint marginTop:6 (341), label marginBottom:6 (318), cardMeta marginTop:4 is fine (8/4) but card paddingVertical via segBtn:12 (363), primaryBtn paddingVertical:16 is on-grid but seg gap:8 mixes with marginBottom Spacing.md(16). 14 and 6 are off-scale. The card marginBottom is Spacing.sm(8) between recipe cards which reads tight for 64px+ list rows (import.md §4 wants 64px rows with clear separation).","f":"Replace 14 → Spacing.md(16), 6 → Spacing.xs(4) or sm(8). Set inter-card gap to Spacing.md(16) for the review list so rows breathe (import.md §3.5 row spacing). Audit every numeric literal in the StyleSheet against Spacing."},{"c":"functionality","s":4,"i":"Every feedback path uses native Alert.alert — success ('Cookbook saved', 299), partial-save (287), all errors (105, 136, 141, 193, 208), paywall (181), save-limit (258), and pre-flight validation (149-159). DS §6.3 and §10.8 explicitly forbid Alert for non-destructive feedback ('No Alert unless the action is destructive or irreversible'; toasts/inline banners instead). import.md §3.9 specifies a full-screen calm SAVED→View/Review success state and §3.10 specifies inline amber error states with Retry-After — none of which exist here. The success Alert with Library/Plan buttons is the product's save-confirmation moment rendered as a system dialog.","f":"Replace the success Alert with the import.md §3.9 success state (CheckCircle 56px success-green, Fraunces 'Saved.', book name, 'In your library' chip, View/Review CTAs). Replace error/paywall/limit Alerts with inline banners (DS §10.8) or the §3.10 error states. Keep Alert only if a genuinely destructive confirm is ever added."},{"c":"parity","s":5,"i":"There is NO web equivalent of cookbook-import. Web RecipeUpload.tsx only references 'cookbook scans' in copy strings (lines 1341, 1350, 1500) and has no PDF pick → /api/cookbook-import/extract → parse → batch review → commitCookbookImport flow. The entire batch-cookbook-import journey (multi-recipe parse, per-recipe exclude, author-vs-match nutrition toggle, paged review, partial-save-on-cap) is mobile-only. import.md §3.1 frames the PDF path as a flag-gated tile but the spec assumes the import surface reaches parity; this whole feature has drifted mobile-only with no carve-out logged.","f":"Either (a) build the web cookbook-import surface reusing src/lib/planning/planImport/* (commitCookbookImport already lives in src), or (b) if web-cookbook-import is intentionally deferred, log an explicit sync-enforcer carve-out + Linear ticket (per no-silent-deferrals) and state it in import.md §5 alongside gaps #5/#7. Today it is an undocumented divergence."},{"c":"photography","s":3,"i":"Zero imagery anywhere. The pick state is a bare dashed-border upload zone with two text lines; the review list shows recipe title + kcal + meta only (no cover thumbnail); the parsing state is a plain ActivityIndicator; there is no success-state dish photo. DS §11.2 and import.md §4 call for editorial dish photography on recent-imports/success and a warm fallback hierarchy (§11.4) — never cold text tiles. import.md §3.3 wants a calm line-art ChefHat/UtensilsCrossed glyph in place of the spinner.","f":"Add a warm fallback (sage→card gradient + pan icon, DS §11.4) thumbnail to each review row. Replace the parsing ActivityIndicator with the line-art glyph + serif step label + thin terracotta/damson progress track (import.md §3.3). Add a dish/cover image or warm monogram to the success state."},{"c":"style","s":3,"i":"Review-row state is communicated by opacity:0.45 + strikethrough only (lines 470, 475) — a flat, cheap exclude treatment with no semantic chrome. The author-vs-match segmented control (segBtnActive: accent.primary at 14% tint, 370) is the only accented element and reads as a generic toggle, not the DS selected-card pattern (§6.2: 2pt terracotta/damson border + 6% tint). The recipe card is a flat warm slab with no leading affordance, checkbox, or selected-border to signal include/exclude — the primary interaction (tap to toggle) has no visible control.","f":"Give included rows a visible checkbox/check affordance (DS §10.1 trailing control) and use the §6.2 selected-card border for included state rather than dimming excluded ones. Keep the segmented control but align active state to the DS selected pattern (border + tint), not tint-only."},{"c":"functionality","s":2,"i":"Pager-based review (Previous/Next, 10 per page, lines 431-456) is an unusual, non-premium pattern for a save-review list — comparable importers (and import.md §3.5) use a single scrollable review list with a sticky running-totals footer. Paging fragments the 'review everything before saving' mental model and the page text 'Page 1 / N' is sans muted with low affordance. Not broken, but off-bar for the editorial-luxury target.","f":"Replace pagination with a single FlatList of all parsed recipes plus a sticky footer (count + Save), per import.md §3.5 running-totals bar. If list length is a perf concern, keep FlatList virtualisation rather than manual paging."},{"c":"style","s":2,"i":"Primary button uses hardcoded color:'#fff' text and accent.primary fill with borderRadius:16 and fontWeight:'700' fontSize:16 — not routed through a shared Button component or CTA type token (cta-primary is Inter 15-16 600). The 700 weight + 16px is heavier than the DS cta-primary spec and the white is a raw literal rather than an on-surface token, risking drift from the rest of the Sloe DS button treatment.","f":"Route the CTA through the shared button primitive / Type.cta-primary token (Inter 600, 15-16pt) and use the DS on-primary text token instead of '#fff'. Set button radius to 12 (radius-md)."}]},{"name":"shopping","model":"sonnet","impl":"apps/mobile/app/shopping.tsx","gaps":[{"c":"photography","s":5,"i":"Every ingredient row is text-only. The locked imagery rule (§11.1) and plan.md §3.9 both mandate a 40×40pt stylised-photoreal ingredient thumbnail on every shopping row (the Julienne benchmark — serif group header + per-ingredient thumbnail + calm checkbox). The capture shows hollow checkbox + name + faint source caption, nothing else. This is the single biggest miss against the premium bar: the list feels like a database export, not a cookbook.","f":"Add a leading 40×40pt FoodImageThumbnail (the same ingredient single-subject component used on verify/log) before the checkbox in each itemRow, 6pt radius, #F6F5F2 fallback fill. Lazy-gen / canonical-key the ingredient image like elsewhere. Apply on web too (the web mirror explicitly lists 'Recipe thumbnail images' as not-shipped — close that gap)."},{"c":"functionality","s":5,"i":"The Progress card shows '0/32' but the active sub-tab pill shows '31'. The card denominator is items.length (raw rows, 32) while uncheckedCount fed to the pill is totalGroupCount (grouped, 31). Two different counts for the same list surfaced 80px apart — reads as a bug to the user.","f":"Make the Progress card count grouped rows to match the pill and the per-section counts: render {checkedGroupCount}/{totalGroupCount} (both already computed) instead of {checkedCount}/{items.length}. progress is already group-based, so only the numerator/denominator text is wrong."},{"c":"style","s":4,"i":"\"Shopping list\" is printed twice in the top chrome: once as the serif H1 (PlanTabChrome title) and again as the active 'Shopping list 31' segmented pill directly beneath it. Redundant landmark label wastes the most valuable vertical space on the screen and reads as unconsidered.","f":"Drop the title to a single source. Either set PlanTabChrome title to a neutral landmark (e.g. brand/'Plan') and let the sub-tab carry 'Shopping list', or keep the H1 and shorten the active pill to 'Shopping'. Mirror whichever choice on the 'This week' side so the pattern is symmetric."},{"c":"spacing","s":4,"i":"Ingredient rows are cramped: itemRow uses paddingVertical Spacing.sm (8) giving a ~38pt row against the spec minimum of 52pt (plan.md §3.9 / DS §10.1 44pt touch-target floor). In the capture the rows are visibly tighter than a premium list and the tap target is below 44pt.","f":"Raise itemRow to a 52pt min-height (paddingVertical Spacing.md=16 or minHeight:52 + center). This also gives the new thumbnail vertical room. Keep the hairline top-border as the divider."},{"c":"spacing","s":3,"i":"Section-header-to-first-row gap is marginBottom:4 (xs) — DS §3.1 specifies lg (16) for 'section label margin-below'. 4pt is too tight; the serif 'Fruit & Veg' header sits almost on top of the first ingredient. Also the inter-row dividers start immediately under it with no breathing room.","f":"Bump the section-header row marginBottom from 4 to Spacing.md (16) (or Spacing.sm=8 at minimum) to match the scale and let the serif header breathe above its rows."},{"c":"style","s":3,"i":"Unchecked checkbox border uses colors.tabIconDefault (#9B93A3, a mid cold-grey) instead of the hairline --border (#E8E2EC). The capture shows dark, heavy-ringed empty circles that read colder/more clinical than the calm Julienne checkbox the spec calls for (border --border unchecked, terracotta/plum fill on check).","f":"Change checkbox.borderColor from colors.tabIconDefault to colors.border (#E8E2EC) to match DS §3.9 and the web mirror (which already uses 1.5px solid var(--border)). Keep the accent.primary fill + white check on checked."},{"c":"style","s":3,"i":"Header action icons are Ionicons (share-outline, trash-outline) — DS §0.1(b) mandates lucide line icons for abstract controls (share, etc.), and the rest of this very file imports lucide (Check, ShoppingCart, Trash2, Users). Mixing Ionicons in the header with lucide in the body is an inconsistent icon family on one screen. The bare destructive-red trash also has no label/affordance framing.","f":"Replace the two Ionicons header actions with lucide Share (Upload/Share2) and Trash2 to match the body icon set and the design system. Keep destructiveSolid for the trash tint per the colour rules."},{"c":"typography","s":2,"i":"The 'Progress' label is Type.body (Inter 14 semibold) — a flat data label. On a premium surface the progress card heading and the count would lean on the serif/hero treatment used elsewhere (the count is an achievement number). It currently reads as generic UI chrome rather than the calm-coach progress moment.","f":"Treat the progress count as a hero numeral: render checkedGroupCount/totalGroupCount in Type.heroValue (Newsreader, tabular-nums) and keep 'Progress' as a quiet Inter label, matching the 'big numerals always serif' rule (DS §2.3.3)."},{"c":"typography","s":3,"i":"Section header treatment diverges across platforms: mobile uses Type.headline (Newsreader 17pt mixed-case, e.g. 'Fruit & Veg') while the web mirror renders categories as an Inter all-caps 11px eyebrow ('FRUIT & VEG'). Same surface, two different typographic systems for the group header.","f":"Pick one and sync. The DS favours serif section headers for editorial moments (Julienne pattern, plan.md §3.9 'serif group headers'); promote the web group header to the Newsreader serif treatment to match mobile, or downgrade both to the eyebrow — but not split."},{"c":"typography","s":2,"i":"The per-row source caption (itemFrom, e.g. 'Chicken Frittata') uses a hardcoded fontSize:11 with colors.textTertiary (#9B93A3) — off the Type ramp and, against the warm card, very faint in the capture (borderline AA for body text). It's also the only thing giving the row context, so it shouldn't be the weakest element.","f":"Move itemFrom to a Type token (caption / label-secondary, Inter 12pt) and lift the colour to colors.textSecondary (#6A6072) so the recipe provenance is legible, not a whisper."},{"c":"parity","s":3,"i":"Mobile and web shopping diverge structurally beyond the documented kanban carve-out: web is a 3-column grid (grid-cols-3, max-w-900) while mobile is a single stacked column (correct for mobile). But web also omits the share/clear-all actions, recipe thumbnails, and uses a different empty-state headline ('Your shopping list builds itself' web vs 'No items yet' mobile) and different checkbox sizes (web 18×18 r9 vs mobile 22×22 r11). The empty-state copy and checkbox sizing should match.","f":"Sync the empty-state headline + body copy across platforms (pick one — web's 'Your shopping list builds itself' is warmer and more on-voice than mobile's flat 'No items yet'). Align checkbox dimensions. Add the ingredient thumbnail to web in the same pass to close §11.1."},{"c":"functionality","s":2,"i":"The empty-state body promises 'grouped by aisle' but the data is grouped by category via sortShoppingCategories (aisle order). The capture's populated state shows 'Fruit & Veg' (an aisle), so this works — but plan.md §3.9 flags recipe-vs-aisle grouping as an open product decision (ENG to file) and the copy commits to aisle. Confirm the aisle taxonomy is real and not falling back to 'Other' for unmatched items (the load path defaults category to 'Other').","f":"Verify aisle categorisation coverage on real plans (not the seeded test data) so the 'grouped by aisle' promise holds and items don't dump into an 'Other' bucket. If recipe-grouping is still under consideration per §3.9, ensure the open ENG ticket exists rather than leaving it implied."},{"c":"style","s":3,"i":"The household 'Shared with…' banner and section cards both use the warm #F6F5F2 card; with the soft cardSoft elevation now default, but the shopping section cards here are styled with an explicit border (borderWidth:1 borderColor:border) and NO cardSoft shadow — so they read flatter than the elevated Today/Plan cards Grace pushed to a 0.16 plum lift. The screen's cards look comparatively flat/cheap next to the rest of the redesigned app.","f":"Apply Elevation.cardSoft (the now-default resting-card lift) to the progress card and each section card so they sit consistently with Today/Plan cards, rather than the flat hairline-only treatment."},{"c":"spacing","s":1,"i":"attributionChip / attributionInitials use hardcoded off-scale values (gap:4 ok, paddingHorizontal:6, width/height:14, borderRadius:7, marginTop:2). 6pt horizontal padding is off the 4/8 scale and 14/7 are arbitrary. Minor, but it's off-grid sizing in a component that does render for household users.","f":"Normalise the attribution chip to the scale: paddingHorizontal Spacing.sm (8) / use a defined avatar size (16) with radius full, gap xs (4). Mirror the same values web-side (web uses 14×14 too)."}]},{"name":"barcode","model":"sonnet","impl":"apps/mobile/app/(tabs)/barcode.tsx","gaps":[{"c":"typography","s":5,"i":"Every heading and the macro values use Inter sans at fontWeight 700, never Fraunces serif. overlayTitle (\"Barcode Scanner\" 18px/700), productName (16px/700), manualTitle/corrTitle (18px/700), and the four macroValue figures (14px/700) are all sans. Design-system §2.3 rule 2+3 (meal/food names always Fraunces; big numerals always Fraunces) and nutrition-log §3.3 type table (serif for headings/food names) require serif here — the editorial register the whole app is built on is entirely absent on this surface.","f":"Load Fraunces and apply it to productName, the manual/correction sheet titles, the scanner idle title, and the four scaled macro numerals (kcal/protein/carbs/fat) per §2.3. Keep Inter for the macroLabel captions and the body hint lines."},{"c":"style","s":4,"i":"The idle-state hint renders as a flat dark-grey slab (Colors.dark.overlay = #000000aa) with no border, radius polish detail, icon, or hierarchy — just two left-aligned text lines. In the no-camera sim it reads as a detached cheap grey block floating over white. No scanner iconography, no editorial framing, no warm-coach voice. Reads utility-app, not luxury.","f":"Give the idle overlay an editorial treatment: a serif title, a lucide scan/Camera icon, calm-coach sub-copy, and the warm-card/overlay treatment with a hairline and the standard sheet shadow (§5). Consider centring it as a guide-card under the reticle rather than a bottom slab."},{"c":"style","s":4,"i":"The scan reticle is a single 2px rounded rectangle in accent.primary+\"80\" (Frost/Damson at 50% opacity) — on white it reads as a faint grey-lavender empty box, indistinguishable from a broken/placeholder frame. Premium scanners (MacroFactor/Cal AI ref in §3.3) use bright targeting corner-brackets, not a full faint outline.","f":"Replace the full-perimeter faint rectangle with four corner-bracket targeting marks in full-opacity accent (Damson/Frost), per the §3.3 \"targeting corners in accent\" spec. Raise opacity so it's legible over a real camera feed."},{"c":"spacing","s":4,"i":"Multiple off-scale paddings/gaps. presetRow gap: 6 (off-scale — should be 8/sm). presetChip paddingHorizontal:10 paddingVertical:5 (off-scale — should be 8/4 or 16/8). All CTAs (permBtn, logBtn, secondaryBtn, retryBtn, manualEntryBtn) use paddingVertical:14 (off-scale, and below the spec's 48px CTA height). manualSub/corrSub use marginTop:-4 (negative-hack off-scale). The Spacing scale is xs4/sm8/md16/lg20/xl24 — none of 5/6/10/14 are on it.","f":"Snap presetRow gap→Spacing.sm(8), presetChip→{px:Spacing.sm, py:Spacing.xs}, all CTA paddingVertical→a value yielding ≥48px height (≈Spacing.md 16 with the font), and replace marginTop:-4 with a real gap token on the parent."},{"c":"functionality","s":4,"i":"Barcode logging is hardcoded to the Snacks slot (commitLog and handleManualLog both insert name:\"Snacks\"). There is no meal-slot picker on this screen at all, so a scanned breakfast item always lands in Snacks. The web dialog (today-barcode-dialog.tsx) has a full Breakfast/Lunch/Dinner/Snacks <select>. This is a real correctness + parity defect, not just chrome.","f":"Add a 4-segment slot pill (Breakfast/Lunch/Dinner/Snacks) above the portion picker per nutrition-log §3.1, default to the time-of-day slot, and pass the chosen slot into the insert instead of the literal \"Snacks\"."},{"c":"functionality","s":3,"i":"No Barcode/Label segmented toggle and no Label-OCR path. nutrition-log §3.3 names Label OCR \"the single highest-value capability gap identified in the benchmark\" (MacroFactor parity) and specifies a [Barcode|Label] toggle in the scanner chrome plus a Serving/Package/Grams portion toggle (Cal AI). Neither exists — the not-found path dead-ends at manual nutrition entry, which requires the user to read the panel themselves.","f":"Per §3.3: add the [Barcode|Label] top-right toggle and the OCR review-card flow; add the Serving/Package/Grams segmented control above the gram stepper. At minimum, ticket the Label-OCR work explicitly (no-silent-deferrals)."},{"c":"functionality","s":3,"i":"No fit-this-in projection on the scanned-product card. The found-product overlay shows scaled macros but not how they fit the day/slot budget. nutrition-log §3.2/§3.3 calls fit-this-in \"ahead of all benchmarked comparables and must not be dropped\" — it's present in the search preview path but absent here, so the barcode path is the weaker logging surface.","f":"Run projectRemaining for the selected slot on every gram change and render the §3.2 projection banner (\"Fits in [slot] — N of M remaining\" in success / \"N over budget\" in amber) below the macro row."},{"c":"parity","s":4,"i":"Mobile and web barcode surfaces are structurally divergent. Web = a Dialog with manual barcode-number entry, recent-foods chips, a meal-slot <select>, an \"Edit calories & macros\" override checkbox on the found product, and a not-found state with three ranked CTAs (Add product / Scan the label photo-fallback / Try another). Mobile = a full-screen live-camera scanner with NO slot picker, NO inline macro-override checkbox on the found card (only a separate correction sheet), and a not-found state offering only \"Enter manually\" (no photo-fallback CTA). The two platforms answer the same job differently.","f":"Reconcile per the mobile-decisions-apply-to-web rule: add the slot picker + photo-fallback CTA to mobile's not-found state, and align the found-product card affordances (override vs correction) so both platforms expose the same capabilities."},{"c":"style","s":3,"i":"Confidence trust signal is hidden behind the redesign_search_results flag. With the flag off (current default capture state), the found product shows only a tiny tertiary \"Verified\"/\"via Open Food Facts\" line in Colors.dark.textTertiary (#857F8B) — low-contrast grey, not the legible Verified/Estimated chip §3.2 wants at-a-glance. Trust posture (§12.3 \"confidence is visible\") is under-served in the default path.","f":"Promote the SearchResultConfidenceChip to the always-on path (or ramp redesign_search_results to 100%), and ensure the chip + source line meet the 4.5:1 contrast bar rather than living at textTertiary."},{"c":"style","s":2,"i":"CTAs and chrome use raw rgba(255,255,255,…) and \"#fff\" literals (servingInput bg, secondaryBtn border, manualInput bg) instead of tokens, and the buttons have square-ish Radius.md (=6px in this theme) where the design system uses radius-md=12 / radius-lg=16 for cards and CTAs. The button corners read tighter/cheaper than the spec's rounded CTA language.","f":"Replace white-literal fills with overlay/card tokens, and bump CTA radius to the design-system radius-md(12)/lg(16) equivalents so the buttons match the rounded premium CTA pattern used elsewhere."},{"c":"photography","s":2,"i":"No imagery anywhere on the found-product card — the scanned item is text-only (name + macro row). The imagery system (§11.1) supports stylised-photoreal single-subject product/ingredient thumbnails, and the not-found path could offer the photo-capture fallback. The surface is visually cold where a small product thumbnail would add warmth and recognition confidence.","f":"Where OFF returns a product image (or a known ingredient match), show a small stylised thumbnail on the found-product card; on not-found, lead with the §3.3 photo/label-capture CTA rather than only manual text entry."},{"c":"typography","s":2,"i":"macroLabel and source captions sit at 11px in textTertiary (#857F8B) — below the type ramp's label-secondary/caption sizes (12–13px) and at borderline contrast. The \"kcal / protein / carbs / fat\" labels under the values are smaller and fainter than the §2.2 caption spec.","f":"Raise macro/source captions to 12px and move from textTertiary to textSecondary so they meet the caption ramp and the 4.5:1 (or 3:1 large) contrast bar."}]},{"name":"weight-tracker","model":"sonnet","impl":"apps/mobile/app/weight-tracker.tsx","gaps":[{"c":"typography","s":5,"i":"No serif anywhere on the screen. Screen title 'Weight & Trends', the 'Weight'/'Journey'/'Historical import depth' section headers, and the hero '54.6 kg / Current' figure all render in Inter sans (fontWeight 700/800). The design system (§2.3 rule 3) mandates Fraunces/Newsreader for screen H1s and 'any number that is the primary focus of a screen or card'. The current weight numeral is the single most important number on this surface and it is in sans.","f":"Apply Type.serif (Newsreader, loaded via @expo-google-fonts/newsreader) to: the 'Weight & Trends' H1 (display-title ~28pt), section headers 'Weight'/'Journey'/'Historical import depth' (display-section 18-22pt), and the current-weight figure. The web mirror already does this — text-[30px] font-medium font-[family-name:var(--font-headline)]. Match it: serif ~30pt for the current kg value."},{"c":"parity","s":5,"i":"iOS standalone is the OLD pre-Sloe path; the web Progress weight card (ProgressDashboard.tsx 'Sloe Figma 492:2', lines 1252-1380) is fully redesigned and diverges hard. Web has: Newsreader serif kg headline (text-[30px]), a Trend/Scale segmented toggle (role=tablist, progress-weight-view-toggle), '↓ N this week' delta with trend icons, a clay area-fill chart, and a 'Goal N · on track for ~date' line. iOS weight-tracker.tsx has none of these. iOS is the PRIMARY surface yet it trails web.","f":"Port the Sloe weight-card treatment from ProgressDashboard.tsx to the iOS surface (or, per the in-code Phase 3 note at lines 1029-1031 and spec §1, collapse /weight-tracker into a redirect to the Progress tab where the canonical redesigned WeightChart already lives). Do NOT leave two divergent weight surfaces — pick the redirect or bring iOS to web parity in the same commit per the mobile-decisions-apply-to-web rule (inverted here: web is ahead)."},{"c":"functionality","s":4,"i":"Logging affordance is a cheap inline TextInput ('54.6') beside an outline 'Save' button. Spec §3.8 calls for the LogWeightSheet pattern: a serif-display 56pt hero numeral, a reassurance subline ('Current: N kg · Last logged [date]'), optional ±0.1 steppers, and a full-width 56pt terracotta/plum primary CTA. The current bare input+button reads transactional and 'cold' — exactly weakness W5 in the spec, unaddressed.","f":"Replace the inline input/Save with the canonical LogWeightSheet entry (bottom sheet, hero serif numeral, reassurance subline, full-width 56pt CTA), or at minimum route the weigh-in through it. If keeping inline, the field must not be a plain rectangle next to an outline button — give it the hero-numeral treatment per §3.8."},{"c":"functionality","s":4,"i":"No Trend/Scale toggle. The MA smoothing is invisible (spec weakness W1, High) — the user sees one plum line and assumes it is their literal weigh-ins. Web already shipped the toggle (weightView state, progress-weight-view-toggle). The single most common confusion on a smoothed weight chart ('why doesn't this match my scale?') is unanswered on iOS.","f":"Add the Trend/Scale segmented pill toggle to the chart card header, matching web's role=tablist implementation. Trend = MA line (current), Scale = raw dots. The shared computeWeightTrend already exposes the data; this is display-only."},{"c":"style","s":4,"i":"The 'Current'/'Goal' stat pair sits as two small sans values in a row inside the card (statValue 18pt/700, statLabel 10pt) and the Goal value is a bare em-dash placeholder. Spec §7.1 mandates a stat-pair header ABOVE the chart: left = serif 28pt current weight + sage caption, right = signed delta. The current layout buries the hero figure as a 'data in a tracker' corner stat (W2/W10).","f":"Promote the current weight to a serif-display 28pt stat-pair header above the chart; keep the signed range delta to its right (already computed as rangeDelta). Demote 'Current'/'Goal' labels to Inter 12pt sage captions. Do not leave 'Goal —' as a naked em-dash with no context line."},{"c":"spacing","s":3,"i":"Off-scale 12px values used directly instead of Spacing tokens. weight-tracker.tsx input paddingVertical:12 (line 601), btn paddingVertical:12 (line 612), the Historical-import-depth pills paddingHorizontal:12 + gap:8 (lines 698,710,712), and journeyBar height:12 / radius:6. The theme Spacing scale is xs:4·sm:8·md:16·lg:20·xl:24 — there is no 12 token, so md:16 or sm:8 should be used. CLAUDE.md and the spacing lens flag any off-scale 12.","f":"Replace raw 12s: input/btn paddingVertical 12 → Spacing.md(16) for a 48pt+ touch target; import-depth pills paddingHorizontal 12 → Spacing.md, gap 8 → Spacing.sm; reconcile journeyBar 12/6 against the token set (use a named height const). Note: the doc design-system §3.1 lists md=12/lg=16, but the actual theme constant has md=16/lg=20 — the implementation must follow the theme tokens, and the design-system doc's spacing table is stale and should be reconciled."},{"c":"spacing","s":3,"i":"Card touch targets fall below the 44pt minimum. The 'Save' button is paddingVertical:12 (=~40pt total height with the 13pt label), under the §3.3 / accessibility 44pt floor; the import-depth lookback pills are paddingVertical:8 (~33pt), well under 44pt. Spec §4 sets CTA height to 56px for weight Save/Log buttons.","f":"Raise the Save button to a 48-56pt height (paddingVertical Spacing.md+ or an explicit minHeight:52) per spec §4; raise lookback pills to minHeight:44. "},{"c":"functionality","s":2,"i":"Range pills (1W/1M/3M/1Y/All via TimeRangeSelector) have no disabled state for insufficient data (spec weakness W3, Medium). On an empty/sparse account a user can tap '1Y' and get a broken/empty chart with no explanation. The capture shows '3M' selected with a populated chart, but the empty-account path is unguarded.","f":"Grey out + make non-interactive any range pill whose data threshold isn't met (spec §3.2 thresholds), with a long-press tooltip 'Log more weigh-ins to unlock this view'. Display-only over the existing smart-bucket logic."},{"c":"functionality","s":2,"i":"Range count divergence vs web and vs spec. iOS standalone exposes 1W/1M/3M/1Y/All but the underlying TimeRange union also carries 6M/9M/12M (used in rangeDaysNominal map, lines 411-419) — and the on-card 'Historical import depth' offers 3/6/9/12 mo — yet the visible toggle omits 6M. Spec §3.2 wants 1W/1M/3M/6M/1Y/All. Web has only 4 ranges (7d/30d/90d/all). Three different range sets across the two platforms + the import card.","f":"Standardise the chart range toggle to the spec set (1W/1M/3M/6M/1Y/All) and reconcile with web's 4-range picker (documented divergence in spec §7 allows web to differ on 6M/9M/12M, but the iOS visible toggle should still match the spec). Make the import-depth presets visibly distinct from chart-range pills so they don't read as duplicate filters (the existing comment at lines 675-682 acknowledges this confusion)."},{"c":"style","s":2,"i":"Card shadow is heavier/looser than the locked one-elevation spec. weight-tracker.tsx cards use shadowOffset {0,2}, shadowOpacity 0.06, shadowRadius 8 (lines 561-565). Design-system §5 specifies shadowOffset {0,1}, shadowOpacity 0.06, shadowRadius 4 for cards on the white base. The 8px radius/2px offset reads as a softer, more generic 'wellness app' float than the crisp 4px hairline-lift spec.","f":"Tighten card shadow to shadowOffset {width:0,height:1}, shadowRadius 4, shadowOpacity 0.06, elevation 2 per §5. Also note shadowColor '#000' should be '#1B1814' (ink) per the spec token."},{"c":"style","s":2,"i":"Journey card milestone markers are flat Ionicons checkmark-circle / ellipse-outline dots in a justify-around row (lines 968-991) — spec weakness W9 / §3.5 calls for differentiated milestone BADGES (filled plum circle with serif numeral when reached, hairline circle when not). The journey progress bar height:12/radius:6 is also a generic chunky bar, not the spec's refined treatment. (Journey card not visible on the empty-account capture but present in code for populated accounts.)","f":"Replace the dot markers with the §3.5 badge style: filled accent.primary circle + serif '25'/'50'/'75'/'100' inside when journey.pct >= m, hairline border circle + sage numeral otherwise. Add the Cal-AI 'N% of goal' flag pill in the card corner."},{"c":"photography","s":2,"i":"No imagery anywhere on the surface — which is mostly correct for a chart-led analytical screen (spec §11 puts photography on north-star/recipe/plan/empty surfaces, not the weight chart). The one gap: the spec's empty/sparse WeightSparseState (§3.7) wants an editorial 'single line on a white ground' minimal illustration for the 0-weigh-in state. On this empty test account the chart still rendered (seeded data), so the sparse-state editorial treatment is untested/likely absent on this standalone route.","f":"Confirm the 0/1/2-weigh-in WeightSparseState renders on /weight-tracker (the standalone only gates the chart on points.length >= 2 at line 801 and otherwise shows nothing — no warm editorial empty prompt). Add the §3.7 sparse editorial state, or rely on the redirect-to-Progress where WeightSparseState exists."},{"c":"typography","s":1,"i":"Supportive copy 'Every check-in gives us better data for you.' is rendered in Inter 12pt centred (lines 851-861). Per §2.2 / §10.7 editorial commentary lines (the calm-warm-coach hedge layer) should use Fraunces/Newsreader italic (display-italic 15-17pt). It currently reads as a generic caption rather than a coaching voice moment.","f":"Render the supportive line in Newsreader italic ~14-15pt sage, matching the editorial-commentary token, so it carries the warm-coach register instead of looking like fine print."}]},{"name":"profile","model":"opus","impl":"apps/mobile/app/profile.tsx","gaps":[{"c":"style","s":5,"i":"The screen has zero editorial identity. Spec §3.2 calls for a profile/identity card at the top (terracotta circular monogram avatar 48x48, serif name 20sp, tier+join label, stats strip with Recipes + Day-streak tiles and 7-dot weekday grid). The capture shows none of this — it jumps straight to a 'Daily Targets' data card. This is the single biggest miss vs premium parity: there is no human, no warmth, no first-class identity moment, so the screen reads as a raw settings form, not Sloe.","f":"Add the spec §3.2 identity block as the first element: circular monogram (Accent.primarySolid #3B2A4D bg, white Newsreader initial), display name in Type.title/headline serif, 'Free · Joined …' label in caption sage, and the two-tile stats strip (BookOpen recipes + Flame streak with weekday dots). Gate behind settings_redesign_v2."},{"c":"typography","s":4,"i":"Edit-form input values render in Inter sans 15pt (styles.input, line 174). Spec §3.7 makes the Calories input an editorial serif moment (Fraunces/Newsreader 24sp). The summary tiles above are correctly serif (Type.heroValue) but the editable numbers — the thing the user actually touches — are flat small sans, so the most important number on the write surface has the weakest hierarchy. The whole 'Edit Targets' block reads like a generic form.","f":"Promote the Calories input value to Type.heroValue serif ~24sp with a 'kcal / day' caption beneath (per §3.7); optionally add a small MacroColors leading dot per macro input. Keep keyboardType numeric. At minimum raise input value size/weight so it doesn't read as body text."},{"c":"spacing","s":4,"i":"Input cells use hardcoded paddingVertical: 12 (styles.input line 174), which is off the codebase Spacing scale entirely (tokens are 4/8/16/20/24/32/40 — there is no 12). The inputs read slightly squat/tight against the 15pt text and break the 44pt min-row guidance for comfortable touch on a write surface.","f":"Replace paddingVertical: 12 with Spacing.md (16) so inputs hit a ~48pt cell, on-scale and matching the standard-card padding rhythm. Reference the token, don't hardcode."},{"c":"spacing","s":3,"i":"Dietary preference chips use hardcoded paddingVertical: 10, paddingHorizontal: 14, gap: 6 (styles.dietaryChip lines 213-215) — all three off-scale (no 10/14/6 tokens). Off-scale chip padding is exactly the kind of inconsistency the spacing lens flags; it makes the chip row drift from the input/card rhythm.","f":"Snap to scale: paddingVertical Spacing.sm (8), paddingHorizontal Spacing.md (16) (or sm+lg pairing), gap Spacing.xs (4). Align with the filter-pill grammar referenced in the comment."},{"c":"spacing","s":3,"i":"Macro summary tiles use paddingVertical/Horizontal: Spacing.sm + 2 = 10 (styles.targetTile lines 148-149) — arithmetic on a token producing an off-scale 10. Inset-tile padding per design-system §3.2 is p-3 (12) / standard 16; 10 is neither.","f":"Use a single scale token — Spacing.md (16) for tile padding, or Spacing.sm (8) if a tighter inset is wanted — never token+2."},{"c":"parity","s":4,"i":"Mobile /profile edits only macros + name + dietary; web Profile.tsx (lines 109-119, 130, 309) additionally edits weight, height, sex, age, activity_level, goal, plan_pace, nutrition_strategy AND measurement_system (metric/imperial). The capture has no body-stats entry row and no units control. This is the documented (settings.md §2 functional gaps) but still-open divergence — a user on iOS cannot change units or body stats from this surface at all, while web can.","f":"Add the spec §3.7 'Body stats & goal' entry row (User glyph, subtitle 'Height, weight, age, activity level', ChevronRight → GoalPaceEditorSheet behind goal_editor flag) and a Units segmented (settings_units_row flag) writing profiles.measurement_system. Ship the goal_editor flag to 100% so the path is real, not a dead row."},{"c":"style","s":3,"i":"Card titles 'Daily Targets' / 'Edit Targets' render in Inter 16/700 (styles.cardTitle line 129). The design system reserves serif (Newsreader/Fraunces, Type.headline) for section headers and the surface already loads it for the tile numerals. Sans bold titles on a serif-numeral card create a mixed register that reads less editorial than Julienne's consistent serif sectioning.","f":"Move card/section titles to Type.headline (Newsreader serif 17/500) per the locked '§2.3 section headers = serif' rule, keeping body/labels Inter. Or convert to ALL-CAPS Inter section eyebrows (Type.label) if a tracker register is preferred — but pick one consistent treatment."},{"c":"style","s":2,"i":"Macro tile icons render at 14pt (Icon size={14}, line 264) — visibly tiny in the capture, floating top-right of each tile with weak presence. Design-system §10.1 / settings.md §3.2 specify 20pt leading/section icons. At 14pt the Flame/Dumbbell/Wheat/Droplet glyphs read as afterthoughts rather than the macro-identity cue they're meant to be.","f":"Bump tile icon size to 18–20pt to match the section icon standard and give the macro colour cue real presence; keep strokeWidth ~1.75."},{"c":"style","s":2,"i":"Both Cancel and Save Targets render as outline buttons of near-equal visual weight (Save = transparent + 1.5px plum border, Cancel = transparent + 1px hairline). On the primary write surface the Save action does not clearly win — it reads as a secondary affordance. Two ghost buttons side by side is a flat, low-conviction footer vs a premium surface where the commit action is unambiguous.","f":"Keep Cancel as the hairline ghost but give Save a clearer primary treatment for the commit moment — either a filled plum (#3B2A4D, white label, the documented conversion-CTA exception) or at minimum a heavier plum-tinted fill (Accent.primarySoft) so the hierarchy between dismiss and commit is obvious."},{"c":"spacing","s":2,"i":"Inter-card gap is Spacing.xxl (32) between the Daily Targets and Edit Targets cards (scroll.gap line 105) with no section eyebrow separating them. Design-system §3.1 uses 24 (2xl) between card sections and 32 (3xl) only between major screen sections. 32 here reads loose given the two cards are the same topic (targets), and the empty band in the capture is conspicuous.","f":"Use Spacing.xl-equivalent 24 between the two same-topic cards (or add a small section eyebrow to justify 32). Reserve 32 for a genuine major-section break."},{"c":"functionality","s":2,"i":"The Display Name field here writes profiles.display_name, but per settings.md §3.2 (shipped 2026-06-04) the Today greeting personalises from user_metadata.full_name set via a separate 'Your name' field in the Personal settings group. A user editing 'Display Name' on /profile may reasonably expect it to change their greeting and it will not — two name fields with overlapping semantics and no on-screen disambiguation is a latent confusion, not a render bug.","f":"Add a one-line caption under Display Name clarifying its scope (e.g. 'Shown on shared/household surfaces'), or unify the two name concepts. At minimum document the divergence on this screen so it doesn't read as the greeting control."},{"c":"style","s":2,"i":"The empty test account makes the form read cold, but the spec-correct fallback (warm editorial empty states, §6 of design system) is not applied here — the Display Name shows a bare 'Your name' placeholder with no warmth and the surface has no imagery/identity to anchor it. (Judging chrome not missing data: the chrome itself offers no warm anchor on a fresh account.)","f":"The §3.2 identity card (monogram + serif name fallback to email initials/'S') is the warm anchor that fixes this — re-stated as a dependency of gap #1; ensure the avatar/name block renders even for a name-less fresh account (initials fallback)."}]},{"name":"household","model":"sonnet","impl":"apps/mobile/app/household-settings.tsx","gaps":[{"c":"typography","s":5,"i":"Screen title \"Household\" is Inter sans, fontSize 20, weight 700 (household-settings.tsx:433). The locked design system (§2.2 display-title; settings spec §4 \"Screen title — Fraunces/Newsreader 28sp bold\") requires the screen H1 in Newsreader serif at 28sp. This is the single most damaging premium miss: the first thing the eye lands on is a cold sans label, not the editorial serif that defines the Sloe/Julienne register.","f":"Render the title with Type.title (or a 28sp Newsreader variant): fontFamily FontFamily.serifRegular/serifSemibold, fontSize 28, color colors.text. Mirror on web (set the h1 to the serif display class, 28px) — web currently uses text-[22px] sans (HouseholdSettingsPage.tsx:796)."},{"c":"typography","s":4,"i":"Zero serif/Type-token usage on the entire surface (grep confirms no FontFamily/Type/Newsreader import). Every string — title, member name \"Member (you)\", section eyebrows, preset labels, Save CTA — is a hardcoded Inter size. The member display name (an identity moment) is sans 13pt (line 650); the design system §2.1/§2.3 reserves serif for names/identity and §3.12 treats the member row as the household's people list.","f":"Route all type through the Type ramp: member display name → Type.headline (serif 17) or at minimum a serif label; preset labels and row primaries → Type.body; eyebrows → Type.label. Pull the title into serif (see title gap). Adopting the tokens also fixes the letter-spacing/weight drift in one pass."},{"c":"spacing","s":4,"i":"Off-scale spacing is pervasive and inconsistent. Spacing scale is {xs:4, sm:8, md:16, lg:20, xl:24, xxl:32}. The file hardcodes: section marginBottom 18 (lines 485,565,695), preset/grid marginBottom 14 (746,819), inner gap/padding 12 and 14 (row padding 14×12 at 629-630, card padding 14 at 714/850, gap 12 at 423-cluster), eyebrow marginBottom 10 (703,754,833), header marginBottom 16 (ok) but header gap 8 (ok), grid gap 6 (853,872), error padding 12 (443). None of 18/14/12/10/6 are on the scale.","f":"Snap every value to the scale: section gaps 18→md(16) or xl(24) consistently; card padding 14→md(16); row padding 14/12→md(16)/sm(8) per spec §3.2 (standard card px16 py16); eyebrow margin-below 10→sm(8) (spec §4 \"8px below\"); grid inter-cell gap 6→sm(8) or xs(4); error padding 12→md(16). Pick ONE section rhythm (spec §4: 24 above eyebrow, 8 below) and apply it to all four sections."},{"c":"style","s":3,"i":"Section eyebrows use colors.textTertiary (#9B93A3 warm grey) with hardcoded letterSpacing 1.4 (lines 578-581, 698-703, 749-754, 828-835). The locked spec §4 + design-system §2.3 require eyebrows in sage --secondary (#7C8466) with +0.08em tracking (= 0.88 at 11pt, the value baked into Type.label). Current grey-on-white reads weaker/colder than the sage the rest of the redesign uses, and the 1.4 tracking is off-token (too wide).","f":"Swap eyebrow color to the sage secondary (Colors.light.textSecondary is #6A6072 — NOT sage; use the explicit Accent/secondary sage #7C8466 per spec) and replace the inline style block with the Type.label token (letterSpacing 0.88). Do all four eyebrows identically."},{"c":"parity","s":4,"i":"Web has NO solo-empty invite card. Mobile renders a prominent household-settings-solo-empty card (lines 485-562: tinted circle + \"Household is solo\" + Invite) when members.length<=1; the web mirror (HouseholdSettingsPage.tsx) jumps straight to the MEMBERS list with only the inline \"Invite\" link. A solo user on web sees a near-empty, purposeless screen — the exact problem the mobile card was added (Group J line 443) to solve. This is undocumented drift, not an intentional carve-out.","f":"Port the solo-empty card to HouseholdSettingsPage.tsx with the same copy (\"Household is solo\" / invite subtitle) and the members.length<=1 gate, matching mobile token-for-token. Pin with a parity test like the other household copy tests."},{"c":"parity","s":3,"i":"Save CTA treatment diverges across platforms. Mobile Save is an aubergine OUTLINE on white (Sloe treatment #1, lines 1019-1042: backgroundColor card, 1.5px Accent.primarySolid border, plum label). Web Save is a FILLED bg-primary button with white text (HouseholdSettingsPage.tsx:663). Per CLAUDE.md \"design decisions for mobile apply to web too\", the primary-CTA treatment must match. Visible divergence on the most prominent action.","f":"Decide one treatment (the Sloe outline is the newer, intentional 2026-06-08 call) and apply on both. Update the web Save button to the aubergine-outline pattern (border-primary, text-primary, white/translucent fill) so the two surfaces read identically."},{"c":"style","s":3,"i":"Solo-empty state \"+\" glyph in a flat tinted circle reads cold/generic (lines 498-510: 48×48 circle, accent+\"1f\" fill, Plus icon). Against Julienne's editorial empty states (which use a soft illustrative or serif-led moment) this is the standard \"add\" placeholder every settings app ships. Design-system §10.7 empty-state pattern wants Newsreader-italic headline + Inter body; here the headline \"Household is solo\" is sans 15pt bold (line 513).","f":"Apply the §10.7 empty-state recipe: headline in Newsreader italic (Type.coach or serif), keep the body in Inter, and let the icon stay a restrained line glyph. This lifts the one hero moment on the solo screen from utilitarian to editorial without adding imagery (correct per spec — no photography on Settings)."},{"c":"spacing","s":3,"i":"Grid cells hardcode height 34 and borderRadius 8 (lines 929-930), inter-cell gap 6 (853,872), and 28px slot-icon gutter (854,873). Row min-height for interactive elements is 44pt per design-system §3.3 / §13 (44×44 touch target); 34pt cells are below the accessibility floor and read cramped. The 6px gaps are off the 4/8 scale.","f":"Raise cell height to >=44 (or keep 34 visual but expand hitSlop to meet 44pt touch target and document it as intentional with the a11y rationale). Snap inter-cell gaps 6→4 or 8. Keep the cell radius on a token (Radius.lg=8 is fine but reference the token, don't hardcode 8)."},{"c":"style","s":3,"i":"Cards use the flat Radius.lg (8) + hairline border with NO elevation. The 2026-06-04 design-direction call (Elevation.cardSoft, theme.ts:591) made the soft plum-tinted lift the DEFAULT resting-card treatment because \"sim cards are blending into the background, figma does not do this\". The members/privacy/presets/grid cards here are plain bordered boxes (lines 597-604, 708-718, 759-766, 843-851) — they blend into the page exactly as that decision was meant to fix.","f":"Wrap the four section cards in the cardSoft elevation (on an outer wrapper since RN overflow:hidden clips iOS shadows) so they lift off the white page like the Today/Figma cards. Verify in a fresh sim capture that the slab reads raised."},{"c":"style","s":2,"i":"Error banner is off-token: borderRadius Radius.md(6) + padding 12 + Accent.destructive+\"55\"/\"14\" inline hex-alpha (lines 442-451). Inconsistent with the §6.2 semantic card pattern and the destructive token family (destructiveSolid #9E3F2E carries text; raw Accent.destructive at the listed alphas may not clear AA for the 12pt error text).","f":"Use the §6.2 semantic-state card recipe + Radius.md token reference, padding md(16), and the destructiveSolid text colour for the message so the error copy clears 4.5:1."},{"c":"parity","s":2,"i":"Member-picker modal radius diverges: mobile uses borderTopLeftRadius/Right 20 (lines 1067-1068) which is off the Radius scale (sm4/md6/lg8/xl12/full) — 20 is the OLD radius ladder. Web modal uses rounded-t-3xl (24px). Neither matches the Radius.xl(12) token nor each other; design-system §10.3 specifies radius-xl(20pt) for sheets but the mobile Radius token table caps xl at 12, so the token and the spec disagree and the code follows neither cleanly.","f":"Reconcile: design-system §4 lists radius-xl as 20 for sheets, but theme.ts Radius.xl=12. Pick the sheet radius once (the §10.3 20pt sheet value), add a Radius.sheet token if needed, and use it on both the mobile Modal and the web dialog so they match."},{"c":"functionality","s":2,"i":"Sticky Save footer uses backgroundColor colors.background + \"ee\" (translucent, line 1011) as the only separation from scrolling content beneath it. On the white page this is a near-invisible scrim; the grid can appear to slide under a barely-there bar. Web uses a proper gradient fade (from-background via-background/90, line 657). Minor parity + polish gap — the mobile footer lacks the gradient feather web has.","f":"Give the mobile sticky footer the same top gradient feather web uses (LinearGradient transparent→background) instead of a flat 93%-opacity fill, so content fades cleanly under the Save bar on both platforms."},{"c":"style","s":2,"i":"Self member-row subtitle \"1252 kcal · 99g protein\" (line 612) is rendered in Inter 11pt textSecondary as plain data — fine — but the spec §3.12 calls for circular monogram avatars 36×36 sage, \"You\" pill on the self row, and a clearer self-vs-other treatment. Current self row only adds \" (you)\" inline text + a chevron; no \"You\" pill, and the macro line competes with the role text on the same row at the same weight.","f":"Add the §3.12 \"You\" pill on the self row and demote the role text relative to the name; keep the macro subtitle. Small change, but it's the difference between a generic contacts row and the dignified identity row the spec specifies."}]},{"name":"health-sync","model":"sonnet","impl":"apps/mobile/app/health-sync.tsx","gaps":[{"c":"typography","s":5,"i":"No serif anywhere on the surface. The screen title 'Health Sync' is Inter/sans (fontSize 20, weight 800) and centered. settings.md §4 mandates the screen title in Fraunces/Newsreader 28sp bold, left-aligned ink. The whole surface reads as a generic settings page, not the editorial-cookbook register.","f":"Render the header title in Fraunces 28sp bold (system-serif Georgia fallback verified in sim), left-aligned, replacing the centered 20pt/800 sans title. Keep the back chevron left of it (Settings-style stacked header), not a centered-title bar."},{"c":"style","s":5,"i":"Card-title glyphs use @expo/vector-icons Ionicons ('heart' on the Apple Health card, 'nutrition' apple-shape on the Nutrition card). Design system §0.1(b) bans non-lucide for abstract controls/nav, and settings.md §3.10 mandates a lucide Heart (sage). The Ionicons 'nutrition' apple is the most off-brand element on the screen — a cartoonish filled glyph that clashes with the lucide line icons used in the category rows directly below it.","f":"Replace the two Ionicons CardTitle glyphs with lucide Heart (Apple Health card) and lucide Apple or Utensils (Nutrition card), 20pt, strokeWidth 1.75 to match the HealthCategoryRow icons. Drop the Ionicons import from CardTitle entirely."},{"c":"functionality","s":5,"i":"Category rows show a trailing empty circle (Ionicons 'ellipse-outline') in the disconnected state. On an empty/disconnected account this reads as an unchecked radio/checkbox the user can tap — it looks like a broken or incomplete selection control, not a status indicator. settings.md §3.10 explicitly calls for a LEADING status dot (green=synced / amber=never synced / muted=connect to enable), not a trailing circle.","f":"Remove the trailing ellipse/checkmark-circle. Add a 8pt leading status dot before each row label: muted #ECEAE4 when 'Connect to enable', amber #C9892C when connected-but-never-synced, success #5E7C5A when 'Synced X ago'. This makes state scannable and removes the false-affordance read."},{"c":"style","s":4,"i":"No section eyebrows. settings.md §3.10 mandates CONNECT · SYNC SETTINGS · NUTRITION ALL-CAPS eyebrows (Inter 10-11sp, +0.08em tracking, sage). The capture shows two unlabelled cards stacked with no grouping language, so the IA reads as an undifferentiated wall rather than a structured trust surface.","f":"Add ALL-CAPS sage section eyebrows above each card: 'CONNECT' above the Apple Health card, 'NUTRITION' above the Nutrition Sync card (and 'SYNC SETTINGS' if the categories split out). Inter 10-11pt, letterSpacing +0.08em, color textSecondary, 24pt above / 8pt below."},{"c":"style","s":4,"i":"Cards read as flat fills with no perceptible elevation or border separation in the capture — they melt into the page. Card uses Radius.lg which in theme.ts is only 8pt (settings.md §4 + design-system §4 call for 16pt radius-lg on settings/primary cards). The 8pt corners plus near-invisible hairline make the cards feel cheap and tight rather than the soft 16pt warm cards the spec describes.","f":"Use a 16pt corner radius for these cards (the design intends radius-lg=16; theme.ts Radius.lg=8 is the mismatch — bump the card to Radius.xl=12 at minimum, ideally a dedicated 16pt token). Ensure the hairline border #ECEAE4 + soft shadow (0 1px 4px rgba(27,24,20,0.06)) actually renders so cards lift off white per design-system §5."},{"c":"spacing","s":3,"i":"Category rows use paddingVertical: Spacing.sm (8pt) giving a ~36pt row height — below the 44pt minimum interactive/row height (design-system §3.3, settings.md §2 accessibility). On the capture the five rows feel cramped against each other with no separators.","f":"Raise each HealthCategoryRow to a 44pt minimum height (paddingVertical ~12pt with the 20pt icon, or set minHeight:44). Add a #ECEAE4 hairline separator between rows (design-system §10.1) so the five categories read as a list, not a dense block."},{"c":"spacing","s":3,"i":"Helper/rationale text under the toggles uses off-scale hardcoded values: marginLeft:28 (to clear the icon) and marginTop:-4 (a negative pull-up hack), plus raw fontSize 11/12. The negative margin and the magic 28 are not on the 4pt Spacing scale and create fragile alignment that will drift if the icon size changes.","f":"Replace marginLeft:28 with a consistent indent token (icon width 20 + gap Spacing.sm 8 = 28, so express it as iconSize + Spacing.sm rather than a magic literal) and drop the marginTop:-4 by tightening the parent gap instead (use a per-row Spacing.xs gap between label and rationale). Map fontSize to the type scale (label-secondary 12-13)."},{"c":"spacing","s":3,"i":"Card internal padding is Spacing.xl = 24pt all sides. Design-system §3.2 specifies standard cards at 16pt (px-4 py-4); 24pt is the hero-ring-card padding. On a dense settings card this reads too loose at the edges while the inner rows are too tight — inconsistent rhythm.","f":"Drop card padding to Spacing.md (16pt) for these standard settings cards, reserving Spacing.xl (24pt) for hero cards only, and reallocate the saved space into row height so the internal rhythm is even."},{"c":"style","s":3,"i":"The 'Clear all imported data' destructive action is a bare centered text link (Accent.destructive, 13pt) floating at the bottom of the Nutrition card with no row chrome or icon — it reads as an afterthought and is easy to fat-finger or miss. The two inline 'Check meal import' / 'Send a test meal' buttons use Accent.primarySoft fills, creating three different button treatments (soft-fill chips, destructive text link, outline CTA) on one screen.","f":"Give the test/probe actions and the clear action a consistent grammar: lucide-led rows (Flask/test glyph per settings.md §3.10, Trash2 for clear) inside the card with proper 44pt rows, destructive in #C9892C/destructive per design-system §10.11. Reserve the outline-CTA only for Connect/Sync."},{"c":"typography","s":2,"i":"Card titles ('Apple Health / Health Connect', 'Nutrition Sync') are Inter 16pt/700. settings.md §3 treats sub-screen card headers as Fraunces display-section (17-22pt, 600) editorial moments. They currently read as plain bold sans labels, reinforcing the generic-settings feel.","f":"Render the two card titles in Fraunces ~18sp/600 (display-section) to match the editorial register the rest of the redesign uses for section headers; keep body/description in Inter."},{"c":"functionality","s":2,"i":"Persistent internal/dev language still leaks in the unavailable-state copy: 'Rebuild with native modules: from apps/mobile run npx expo prebuild ... open ios/Suppr.xcworkspace'. This is developer instruction text that ships to users in a non-dev build's !available branch, referencing the old 'Suppr' name and raw shell commands — exactly the 'internal language needs to be removed' TF feedback class.","f":"Gate the prebuild/Xcode instruction copy behind __DEV__; show end users a plain-English 'Apple Health isn't available on this device' message only. Also note the residual 'Suppr.xcworkspace' / Suppr naming vs the Sloe rebrand."},{"c":"parity","s":2,"i":"Mobile imports several Sloe-renamed strings ('Sloe test write', 'Privacy → Health → Sloe') but the description copy and the !available branch still say 'Suppr' in places (e.g. 'Suppr development build', 'Suppr.xcworkspace'), and 'Tap Sync Now to import new items into Suppr.' in handleTestImport. Inconsistent brand naming within one file.","f":"Sweep this file for remaining 'Suppr' literals in user-facing copy and align to 'Sloe' (Sync Now import alert, Expo-Go/unavailable copy). Keep file paths/bundle refs as-is only where they are genuine system identifiers."},{"c":"parity","s":1,"i":"This Health Sync sub-screen has no web mirror (confirmed: src/app/components/Settings.tsx has no Apple Health section). Per settings.md §1 this is an intentional divergence (no Health equivalent on web), so it is NOT a parity bug — BUT the 'Simple labels only', import, and share-to-Health preferences therefore have no documented web home and no 'why this is mobile-only' note on the surface itself.","f":"No code change required for parity (intentional carve-out per spec). Confirm the divergence is logged in the sync-enforcer carve-out list; optionally add a one-line note in the spec that import/export prefs are mobile-only by design."},{"c":"photography","s":1,"i":"No imagery expected or missing on this surface — settings.md §4 explicitly states Settings is a data/control surface and the meal-photography / ingredient-illustration rules do not apply. The capture correctly shows no cold/empty photo tiles. Flagging only to confirm: do NOT add FLUX photography here.","f":"No action — absence of imagery is correct per spec. Keep the surface photo-free; the only decorative element permitted is the (not-present-here) avatar monogram on the parent Settings screen."}]},{"name":"recipe-create","model":"sonnet","impl":"apps/mobile/app/recipe/create.tsx","gaps":[{"c":"typography","s":5,"i":"The screen H1 'What are you making?' renders in Inter sans (raw fontSize:22, fontWeight:700 via styles.sectionTitle, line 725-730). The design system locks serif (Fraunces/Newsreader) for screen H1 + onboarding step questions at display-title 32-40pt (_design-system.md §2.2/§2.3 rule 1, recipes.md §0 'display' role 28-32pt serif). This is a 5-step guided creator — the step question is the editorial moment of every step and it is the single most impactful serif miss across the surface.","f":"Set sectionTitle to FontFamily.serifSemibold (Newsreader), ~28pt, lineHeight ~32, via Type.display (or a serif variant). Apply to all five step questions ('What's in it?', 'How do you make it?', 'Macros look right?', 'Save your recipe')."},{"c":"typography","s":5,"i":"The entire wizard bypasses the canonical Type ramp and FontFamily tokens — every text node uses inline raw fontSize/fontWeight (sectionTitle 22/700, sectionSub 14, label 12/700, servingsValue 24/700, ingName 14/600, etc.). Nothing imports Type or FontFamily. _design-system.md §2.3 rule 4 ('no hardcoded font sizes — use the scale tokens') and rule 3 ('big numerals always serif') are both violated. This is why the screen reads as a stock form, not Sloe.","f":"Import { Type, FontFamily } from '@/constants/theme' and map: H1→serif display, sub→Type.bodyMuted, label→Type.label, servings value→Type.heroValue (serif) with tabular-nums, ingredient name→Type.body. Remove the bespoke inline sizes."},{"c":"photography","s":4,"i":"The 'Add photo (optional)' tile is a cold dashed-border empty box with a grey line-icon camera and uppercase tertiary label (styles.photoFallback, lines 758-770; rendered 1032-1037). _design-system.md §0.1 explicitly says the camera 'Photo' surface MAY be a warm stylised-photoreal image in the ingredient-single-subject style, and §6.3/§11.4 ban cold/grey empty chrome — empty states should read warm, never like a loading or disabled state. This is the hero area of step 1 and it currently reads cold and cheap.","f":"Replace the dashed grey box with a warm fallback: either the brand camera/object image (same FLUX pipeline as ingredients) on a #F6F5F2 fill, or a sage→cream gradient tile with the camera glyph in sage #7C8466 — matching the RecipeHeroFallback treatment already shipped on Library cards (recipes.md §11.4). Drop the dashed border."},{"c":"functionality","s":4,"i":"The servings stepper is a bare −/value/+ row (styles.servingsRow + circular servingsBtn, lines 771-794), exactly the 'looks like a form field, not a deliberate stepper' weakness the spec calls out (recipes.md §2.2 + §3.2 'Servings stepper boxed, new'). The value '4' sits unboxed and in sans, so the control reads as raw text between two pills.","f":"Wrap the count in a boxed #F6F5F2 container (hairline border, 8pt radius, ~32-40pt) per recipes.md §3.2, and render the numeral in serif Type.heroValue with tabular-nums. accessibilityRole='adjustable' + accessibilityValue so VoiceOver reads it as a stepper."},{"c":"spacing","s":3,"i":"Input vertical padding is off-scale: paddingVertical:14 on styles.input (line 743) and macroFieldInput padding:10 (line 897), stepInput uses Spacing.md (16). The canonical Spacing scale (theme.ts) has no 14 or 10 — values must be xs4/sm8/md16/lg20/xl24. 14 and 10 are bespoke one-offs that break the 4pt grid and make field heights inconsistent across steps.","f":"Set input paddingVertical to Spacing.md (16) or sm (8)*; macroFieldInput padding to Spacing.sm (8); audit all numeric paddings in the StyleSheet (also primaryBtn paddingVertical:16=Spacing.md OK, secondaryBtn 14→16, backHit padding:6→Spacing.xs*2 or hitSlop only)."},{"c":"spacing","s":2,"i":"The progress-bar segment gap is a raw 4 (styles.progressRow gap:4, line 703) and progressDot height is a raw 4 with radius 2 — fine on the grid (xs) but hardcoded as literals rather than Spacing.xs, and the row uses paddingHorizontal:Spacing.xl (24) while the scroll body also uses Spacing.xl, so the progress track and content share an edge that the capture shows slightly tight against the 'What are you making?' block (progress→H1 gap is only Spacing.md 16 via scroll padding). The eyebrow→progress→title rhythm is cramped vs the airy Figma.","f":"Use Spacing.xs for the segment gap explicitly; add ~Spacing.xl (24) breathing room between the progress row and the first section block (the system's '2xl above section eyebrow' rhythm, §3.1)."},{"c":"typography","s":2,"i":"The 'NEW RECIPE' eyebrow uses letterSpacing:2 at fontSize:11 (styles.topTitle, lines 688-693) ≈ 0.18em — more than double the system eyebrow tracking of +0.08em (Type.label = 0.88 at 11pt; _design-system.md §2.2 section-eyebrow). It reads as over-tracked vs every other eyebrow in the app.","f":"Use Type.label (letterSpacing 0.88) or set letterSpacing to ~0.88 (0.08em) for parity with the rest of the product's ALL-CAPS eyebrows."},{"c":"style","s":3,"i":"The Continue CTA is a transparent plum outline (styles.primaryBtn, lines 928-938). On cold open of step 1 the title is empty so advanceEnabled is false and the button drops to opacity 0.45 (line 1359), which the capture shows as a faint grey ghost button with near-invisible label. An outline-only disabled CTA at 45% reads as broken/dead on first impression rather than 'fill in the field above'. Premium creators (Julienne, Crouton) keep the primary visible and let the field validation guide.","f":"Either (a) keep the outline visible and add an inline helper ('Add a name to continue') instead of dimming to 0.45, or (b) raise the disabled opacity floor to ~0.6 and keep the border at full strength so it reads as 'not yet', not 'dead'. Consider the filled plum slab for this single conversion-adjacent CTA given the outline reads weak when disabled."},{"c":"style","s":3,"i":"Input fill uses cardElevation.liftBg ?? colors.card (#F6F5F2) on a #FFFFFF page with the soft cardSoft shadow now default (theme.ts Elevation.cardSoft). In the capture the recipe-name field and photo box read as flat #F6F5F2 rectangles with no perceptible lift — the same 'cards blending into the background' problem Grace flagged (theme.ts cardSoft comment). The field and photo tile are barely separated from the page.","f":"Verify cardElevation.shadowStyle is actually applied to styles.input (it is NOT — only photoFallback/ingCard/stepRow/totalsCard/saveCard spread shadowStyle; the text input does not). Add the soft lift to the input + ensure the photo tile lift renders on-device, or give inputs a hairline #E8E2EC border so they read as deliberate fields."},{"c":"style","s":2,"i":"The character counter '0/80' (lines 1051-1055) renders in textTertiary 11pt right-aligned and is always visible even at 0 chars. A persistent '0/80' on a pristine field is low-polish noise — premium forms reveal the counter only as the limit approaches (e.g. last 20 chars).","f":"Show the counter only when title.length > TITLE_MAX_LENGTH - 20 (or hide at 0). Keep it textTertiary but make it conditional so the cold-open screen is cleaner."},{"c":"functionality","s":2,"i":"Step 1 collects only name + photo + servings, but there is no description field anywhere in the wizard (description is hardcoded null on save, line 558) — yet the Recipe Detail spec (recipes.md §3.2) renders a 'Description card'. A recipe created via the wizard can never have a description, so the detail surface's description card is permanently empty for wizard-created recipes. This is a quiet feature gap, not visible in the capture but confirmed in code.","f":"Either add an optional description field (step 1 or 3) or explicitly document description-on-wizard as out-of-scope with a Linear ref in the save handler (no-silent-deferrals rule). Currently `description: null` is unannotated."},{"c":"parity","s":3,"i":"The web mirror (src/app/components/RecipeUpload.tsx, 2320 lines) is a single-screen form, not a 5-step wizard — this is a DOCUMENTED carve-out (CreateRecipeWizard.tsx header + recipes.md §4: 'wizard pacing wouldn't help on desktop'), so the step PACING divergence is intentional, not drift. But the per-step VISUAL treatment must still match the shared system, and it doesn't: web uses serif plum headings + var(--radius-card-lg) + shadow-lg cards (RecipeUpload lines 1417-1496), while the iOS wizard uses sans inline type + Radius.md(6) inputs + mostly flat fills. The two surfaces will look like different products on the same step content.","f":"Bring the iOS wizard onto the same serif headings + card-lg radius + soft-lift treatment the web form already uses, so name/photo/servings/macros read identically cross-platform even though the navigation model differs. Track as the parity action under recipes.md §4 'boxed servings stepper' + 'verb row' rows."},{"c":"style","s":2,"i":"Radius mismatch vs spec on this surface: recipes.md §0 locks cards at 12pt and inputs/images at 8/12pt, but the wizard inputs use Radius.md which is now 6pt (theme.ts Radius lock 2026-05-22) and the photo tile uses Radius.lg=8. So fields are tighter-cornered (6pt) than the 12pt the recipes spec calls for. The 2026-05-22 radius tightening (8/6/4/12) post-dates the recipes spec, so there's a genuine token-vs-spec conflict — but per _design-system.md §0 the system file/theme wins; either way the inputs at 6pt read sharper/more clinical than the warm 12pt the surface intends.","f":"Reconcile: if 12pt is the intended warm radius for recipe inputs/cards, use Radius.xl (12) on input/photo/ingCard; if the 6pt system lock is canonical, update recipes.md §0 to 6/8/12 so the spec stops claiming 12pt cards. Don't leave the conflict unresolved."}]},{"name":"create-recipe-form","model":"opus","impl":"apps/mobile/app/create-recipe.tsx","gaps":[{"c":"functionality","s":5,"i":"RENDERING BUG: the sticky 'Save Recipe' footer overlaps and sits ON TOP of the live INGREDIENTS section header, its helper text, and the Paste list / Scan photo quick buttons (visible in capture — footer rule + 'Save Recipe' label cut through the grey helper copy). The ScrollView contentContainer uses paddingBottom: 120 but the footer is absolutely positioned with safe-area + Spacing.md padding, so on shorter content the footer floats over interactive form rows instead of below a reserved gutter. This is a tappable-content occlusion bug, not just a cosmetic one.","f":"Measure the footer height (onLayout) and set ScrollView contentContainerStyle.paddingBottom to footerHeight + insets.bottom + Spacing.xl, or render the footer inside the KeyboardAvoidingView flow below the ScrollView (flex layout) so it can never overlap scrollable rows. Verify in sim that the Ingredients header + quick-add row clear the footer when the form is short."},{"c":"typography","s":5,"i":"No serif anywhere on the screen. The design system mandates Fraunces/Newsreader for screen titles and editorial moments (§2.3 rule 1; recipes.md display role 28–32pt). The header reads 'New recipe' in 13pt Inter 800 with letterSpacing:3 ALL-the-way-tracked — that is a caption/eyebrow treatment masquerading as a title, the single biggest reason this screen reads as a generic settings form rather than an editorial cookbook. Web mirror already renders a real serif H1 (font-[family-name:var(--font-headline)] text-3xl).","f":"Replace the tracked-Inter top title with a Fraunces display title. Either a left-aligned 28pt Fraunces 'New recipe' below the Cancel bar (matching web's text-3xl H1) or a centred Fraunces 17–20pt nav title. Load Fraunces via expo-font and verify the glyphs render in a sim capture before push (system serif fallback otherwise)."},{"c":"photography","s":4,"i":"The cover image control is a cold empty grey/cream dashed box with a generic camera outline + 'ADD PHOTO' eyebrow. §11.4 forbids a neutral grey placeholder and the recipes spec calls for a warm cream gradient (#F6F5F2→#ECEAE4) with a sage pan/pot glyph, never a neutral tile. It currently reads as an unstyled file-upload affordance. Worse, there is a hard parity break: the web mirror seeds a real DEFAULT_COVER_IMAGE (Unsplash food photo) so the web form looks finished while mobile looks empty.","f":"Replace the dashed grey placeholder with the warm RecipeHeroFallback tile (sage→cream gradient + sage cookware glyph per §11.4), same component the Library/Discover cards now use. Use a tangible warm camera object per §0.1(a) for the 'Add photo' affordance rather than a flat line camera if a hero-photo CTA is wanted. Decide and align the cover-seed behaviour across platforms (either both seed a placeholder hero or neither)."},{"c":"spacing","s":4,"i":"Input fields use Radius.md = 6pt corner radius. The recipes spec and design-system §4 want 12pt (radius-xl on mobile maps to 12) for input fields / standard cards. 6pt reads boxy and cheap against the rounded Julienne language. The image placeholder uses Radius.lg = 8pt (spec wants 12–16pt outer card clip). Every surface on this form is under-rounded.","f":"Move text inputs, the paste textarea, the publish row, and meal-type chips to Radius.xl (12pt). Move the image tile to 12–16pt. Audit the create-recipe StyleSheet for every Radius.md usage and bump to the spec radius."},{"c":"spacing","s":3,"i":"Pervasive off-scale padding. Inputs use paddingVertical: 14 (not on the 4/8/16/20 scale). addBtn uses paddingVertical: 14. Quick buttons use paddingVertical: 10 + paddingHorizontal: 12. MealTypePicker chips use paddingHorizontal: 12, paddingVertical: 8, gap: 4 hardcoded, and the chip label section eyebrow is fontSize 11 with letterSpacing 1 (the form label uses letterSpacing 1 too — inconsistent with the system +0.08em eyebrow spec). 12 and 14 and 10 are all off the canonical Spacing set (xs:4 sm:8 md:16 lg:20 xl:24).","f":"Snap every padding to the Spacing scale: inputs paddingVertical Spacing.md(16); quick buttons + meal chips paddingHorizontal Spacing.md(16) / paddingVertical Spacing.sm(8); replace hardcoded gap:4 with Spacing.xs. Inputs should clear the 44pt min touch target (16pt vertical padding + 16pt text ≈ 48pt — currently borderline)."},{"c":"style","s":3,"i":"Section labels are all rendered identically as 11–12pt Inter 700 uppercase letterSpacing:1 in textTertiary — RECIPE NAME, DESCRIPTION, SERVINGS, MEAL TYPE, INGREDIENTS all read at one flat weight with no editorial hierarchy. The design system wants section eyebrows in sage (--secondary) at +0.08em tracking with 24pt above / 8pt below rhythm (§2.2 rule 6, §10.11). Tertiary grey is lower-contrast than the sage spec and the uniform treatment gives the form no scannable structure.","f":"Standardise on the section-eyebrow token: Inter 10–11pt 600, letterSpacing ~+0.08em, colour --secondary (sage #7C8466 / accent-aware), Spacing.xxl(32) above each section and Spacing.sm(8) below. This gives the editorial section rhythm the rest of the redesign uses."},{"c":"style","s":3,"i":"The primary 'Save Recipe' CTA is an aubergine OUTLINE (transparent fill, 1.5px border, ink label) per the in-file treatment note. On the final submit of a creation flow this reads as a secondary/ghost action — it lacks the weight of a primary commit and competes weakly with the dark sticky-footer pattern used on Recipe Detail ('Log all' is a filled #1B1814 bar). The form's most important action looks like a tertiary button.","f":"Promote the submit to a filled primary (Clay/Damson per accent rules) or a dark #1B1814 filled bar matching the Recipe Detail sticky footer, 48–52pt height, Fraunces 15pt label per §10.4/spec. Keep the outline treatment only for genuinely secondary actions. Gate behind the surface redesign flag."},{"c":"parity","s":3,"i":"Source-entry model diverges hard between platforms. Mobile is a single scrolling form with Paste list / Scan photo / Scan barcode + voice/photo sheets and a Publish switch. Web RecipeUpload is a create/import dual-mode component with a different richer entry flow (import queue drawer, GoPublicDialog attestation, USDA hit pickers, structured ingredient rows). The recipes spec §3.5 wants a 4-tile serif source picker (link/video/photo/manual) on BOTH; neither matches it, and mobile lacks the GoPublicDialog attestation UI (it uses a one-shot Alert instead of the web checkbox dialog).","f":"Align both to the §3.5 4-tile source picker and converge the publish-attestation UX (ENG-700 convergence). At minimum, document the divergence as an intentional carve-out with a Linear ID rather than leaving two unrelated implementations; do not leave the mobile Alert-attestation vs web dialog-attestation gap unticketed."},{"c":"style","s":2,"i":"The quick-add row (Paste list / Scan photo / Scan barcode) uses three identical low-emphasis hairline pills with Ionicons line glyphs — there is no visual signal that 'Scan photo' is the magic/viral path. The recipes spec (§2.6, §3.5) flags exactly this: source options as a 'plain action sheet — no visual affordance for which sources work best.' Visually these three buttons read as a generic toolbar.","f":"Differentiate the primary import affordance (Scan photo / paste from clipboard) per §3.5 — e.g. a full-width terracotta/clay clipboard quick-action when a URL/list is detected, and lift the photo path visually. Use the warm tangible camera object for the photo tile per §0.1."},{"c":"style","s":2,"i":"Ionicons are used throughout (camera-outline, clipboard-outline, scan-outline, barcode-outline, cafe/sunny/restaurant for meal types, checkmark-circle, close-circle). The design system standardises on lucide line icons for abstract controls (§0.1(b)) and the rest of the redesigned surfaces use lucide-react-native. Mixing Ionicons here is an inconsistency that subtly cheapens the surface and diverges from the icon set used on Library/Detail.","f":"Swap Ionicons for the lucide-react-native equivalents used elsewhere (Camera, ClipboardList, ScanLine, Barcode, Coffee/Sun/UtensilsCrossed, CheckCircle, XCircle) so the whole product shares one icon family. Cross-reference the meal-slot icons against the Library card set."},{"c":"typography","s":2,"i":"Meal-type chips and recipe-name placeholder are fine on legibility but the 'Per serving' totals card renders values in Inter 800 18pt tabular-nums. Per the type ramp, the macro/kcal hero values on a card are an achievement number and should be Fraunces (display-subtitle ~20–22pt) — §2.3 rule 3 ('big numerals always Fraunces'). Currently they read as dense tracker data, missing the editorial register the redesign uses for macro tile values.","f":"Render the per-serving kcal + macro values in Fraunces (display-subtitle) keeping tabular-nums, with Inter captions ('kcal','protein') below. Match the macro tile treatment used on Recipe Detail."},{"c":"functionality","s":2,"i":"The 'Publish to community' switch uses Accent.success (green) for its track/thumb. Per the colour system, success green is reserved for ring-under-budget / goal-hit / verified states; a publish toggle is not a success state. Using green here is an off-role colour use (and on an empty test account the toggle is the only colour on an otherwise monochrome form, drawing the eye to the wrong control).","f":"Switch the toggle's active colour to the brand accent (Clay/Damson) used for active controls, not Accent.success. Keep success green for genuine success/verified states only."},{"c":"spacing","s":2,"i":"Servings is a lone 80pt-wide input floating left with no stepper affordance — the recipes spec (§3.2) explicitly calls out 'bare input looks like a form field, not a deliberate stepper' and wants a boxed −/value/+ stepper. On this create form the single narrow numeric field reads as an unfinished form control and wastes the row.","f":"Replace the bare numeric input with the boxed −/[n]/+ servings stepper specified for Recipe Detail (#F6F5F2 boxed value, hairline border, 32pt buttons), shared as one component across create + detail."}]},{"name":"import-shared","model":"opus","impl":"apps/mobile/app/import-shared.tsx","gaps":[{"c":"style","s":5,"i":"Entire idle flow (wordmark, title, body, paste field, Import button, Use clipboard, Import from photo) is crammed into ONE monolithic cream panelCard slab (borderRadius 24, border + 40px padding). The spec §3.2 wants a header + paste-field-on-white + source-trust-chip row + RECENT IMPORTS as DISTINCT sections sitting on the white page ground. The single boxed slab reads as a placeholder modal, not a premium editorial import surface — it is the dominant reason this surface feels 'rough' not 'premium'.","f":"Unbox the idle state: render the header (Sloe mark + serif title + body) and the paste field directly on white #FFFFFF per §3.2. Reserve the cream #F6F5F2 card for the paste field fill only (56px, Radius 12). Move 'Import from photo'/'Use clipboard' to tertiary rows below, source chips and RECENT IMPORTS as their own sections separated by 32px (Spacing.xxl). Drop the outer panelCard wrapper for idle."},{"c":"functionality","s":5,"i":"The 'IMPORT FROM' grid (TikTok / Instagram / YouTube / Website) is a FAKE four-way router: all four tiles call onPasteFromClipboard (import-shared.tsx:2022-2025). The plum-tinted icon boxes (accent.primary + '22') make them read as four separate routes. This is audit gap #6 — a discoverability AND honesty failure flagged in import.md §3.2 and still live.","f":"Per spec §3.2: demote to a single non-tappable trust-affordance row — small #F6F5F2 chips (32×24, Radius 8) holding only the platform monogram, no onPress, with an Inter 12px sage 'Works with' label. Platform-specific guidance already surfaces via the inline hint below the field. Remove the tinted icon boxes so they stop reading as buttons."},{"c":"functionality","s":4,"i":"'Import from photo' is shown to ALL users with no Pro lock; photo OCR is Pro-gated server-side (403 pro_required), so free users tap and fail at request time. Audit gap #1, flagged in import.md §3.1/§3.7 and unresolved here.","f":"Add a Lock badge (12px amber #C9892C) + '(Pro)' Inter 12px amber on the photo affordance; route Free users to the paywall on tap, Pro users to the picker. Surface the gate before the tap, not after."},{"c":"typography","s":3,"i":"Section eyebrows 'IMPORT FROM' and 'RECENT IMPORTS' render as Inter 13px weight 600, letterSpacing 0.5, colour textSecondary (import-shared.tsx importSourcesLabel/recentLabel). The design system §2.2 section-eyebrow role wants Inter 10–11px, weight 600, +0.08em (~1.1px) tracking, uppercase, sage #7C8466. 13px at 0.5 tracking reads as a heavy sub-label, not a delicate editorial eyebrow.","f":"Drop to 11px, set letterSpacing ~1 (≈ +0.08em), colour sage; keep uppercase. Apply the same eyebrow token used elsewhere in the redesign so all caps labels are consistent."},{"c":"style","s":3,"i":"Icon set is @expo/vector-icons Ionicons (logo-tiktok, logo-instagram, logo-youtube, globe-outline, clipboard-outline, camera-outline, restaurant-outline) throughout the idle state. The locked icon rule (design-system §0.1b) says abstract controls/nav glyphs MUST be lucide line icons; brand platform logos are an acceptable exception but the generic globe/clipboard/camera/restaurant glyphs should be lucide (Link2, Clipboard, Camera, UtensilsCrossed) for system consistency. Mixed icon families read as unpolished.","f":"Migrate the non-brand glyphs to lucide-react-native (Link2/Clipboard/Camera/Globe), ink or clay active per §0.1b. Keep platform monograms for the trust-chip row only."},{"c":"spacing","s":3,"i":"Off-scale radii on the two most prominent controls: the paste input and the primary Import button both use hardcoded borderRadius: 16 (import-shared.tsx input/primaryBtn), but the mobile Radius scale tops out at xl=12 (sm4/md6/lg8/xl12/full). 16 is not a token. The spec §3.2 specifies 12px on the paste field. The panel slab itself is Radius.xl*2 = 24 (a doubled token, also non-canonical).","f":"Set the input and primary button radius to Radius.xl (12) to match the spec's 12px field and the rest of the system. If a softer pill is wanted on the CTA, use Radius.full; do not use the orphan 16."},{"c":"spacing","s":3,"i":"panelCard padding is Spacing.xxxl (40) on all sides — far looser than the standard card padding (16, Spacing.md) the design system §3.2 prescribes. Combined with the monolithic slab this produces a lot of dead cream around sparse content, amplifying the placeholder feel. The source tiles also use a raw paddingHorizontal: 8 / paddingVertical: 16 (8 is off the icon-box rhythm and was a papercut workaround for label truncation).","f":"If the slab is retained for any state, bring padding to Spacing.xl (24) max. Once the idle is unboxed (gap #1), the 40px padding disappears. Re-derive source-chip padding from the 4pt grid once they become non-interactive chips."},{"c":"photography","s":3,"i":"The idle screen has zero imagery — it is all chrome (wordmark, text, field, glyph tiles). Julienne's import/add entry leans on warm editorial framing; the design-system imagery rule (§11) calls for warm treatment over cold tiles. The source tiles are cold flat glyphs in tinted boxes. There is no editorial illustration or warm anchor, so the surface feels utilitarian rather than the 'editorial cookbook' register the brand promises.","f":"Either (a) keep it text-forward but warm — replace the tinted glyph tiles with the calm trust-chip row and let the serif header carry the surface — or (b) add a single small warm editorial anchor (e.g. a painterly enamel-pot / saucepan single-subject per §0.1a) above the title, in the ingredient single-subject style. Do NOT add a cold 3D chrome render (banned §0.1b)."},{"c":"parity","s":4,"i":"Web RecipeUpload (src/app/components/RecipeUpload.tsx) diverges from this iOS idle surface on three fronts: (1) NO 'IMPORT FROM' source row at all — the honest trust-chip pattern can't be matched because the grid doesn't exist on web; (2) NO caption-preview/trust path for IG/TT links (gap #2) — web hits the og-scrape directly with no 'We never fetch the post itself' framing; (3) web 'How this fits your day' is a single-line % sentence + a recharts MacroWheel pie (line 2110), while mobile shows a 4-tile 'of {target}' layout. Neither platform yet implements the spec's prescribed thin labelled per-macro bars + verdict line (§3.5), but the platforms also disagree with EACH OTHER.","f":"Per the §5 parity table: bring the caption/trust card to web (gap #2), unify the 'fits your day' presentation across platforms (ideally to the spec's labelled bars + Lifesum verdict line), and decide the source-trust-chip treatment on both. Gate behind recipe-import-redesign flag; ship the visual change on both platforms in the same commit per the cross-platform rule."},{"c":"style","s":2,"i":"Recent-import source badges are hard-coded brand-colour rectangles: recentBadgeTT = solid #000, recentBadgeIG = solid #E4405F (import-shared.tsx). These raw brand hexes are outside the locked palette and read as loud stickers against the warm/plum system. The spec §3.2 wants a neutral mono badge (#F6F5F2 bg, #1B1814 text, #ECEAE4 border, Radius 6).","f":"Replace the solid black / Instagram-pink badges with the spec's neutral mono chip (cream fill, ink text, hairline border, 6px radius) so all four source types (TT/IG/YT/W) share one calm treatment."},{"c":"typography","s":2,"i":"The screen H1 is the brand wordmark 'Sloe' (Newsreader) followed by 'Paste a recipe link' as the serif title. The spec §3.2 prescribes 'Import a recipe' as the Fraunces/Newsreader 22px H1 with 'From any link, social post or website.' as the sub. Leading with the wordmark on a deep sub-screen is redundant (the nav bar already shows 'IMPORT') and the heading hierarchy doesn't match the spec.","f":"Drop the in-card wordmark on this sub-screen, promote 'Import a recipe' to the serif H1 and use the spec sub-copy. Keep the Sloe wordmark for top-level/brand surfaces, not a pushed import screen that already has an 'IMPORT' eyebrow in the top bar."},{"c":"typography","s":2,"i":"Top-bar title 'IMPORT' uses fontWeight 800 with letterSpacing 3 in the clay/plum accent (topTitle). Weight 800 + 3px tracking is heavier/wider than the section-eyebrow ramp (§2.2 wants 10–11px 600 +0.08em). It reads as a shouty all-caps label rather than the calm editorial eyebrow the system uses elsewhere.","f":"Bring the top-bar title to the eyebrow token (11px, weight 600, ~1px tracking, sage or ink) or use a Newsreader title-case label; avoid 800 weight which exists nowhere else in the ramp."},{"c":"functionality","s":2,"i":"The platform inline hint (shown when an IG/TT/YT URL is typed) is styled as a tinted clay box (accent.primary + '12' bg, '33' border) — visually it competes with the primary Import button directly below it and uses the clay accent for an informational note, whereas the system reserves clay for CTAs/active states and uses sage/amber for advisories.","f":"Restyle the inline hint as a calm note: #F6F5F2 fill or a sage left-border per the design-system 'recovery/note' card variant (§6.2), Inter 12px sage text. Keep the share-outline glyph but in sage. This stops two clay elements stacking."}]},{"name":"weekly-recap","model":"sonnet","impl":"apps/mobile/app/weekly-recap.tsx","gaps":[{"c":"typography","s":5,"i":"The entire screen renders in system sans. No Fraunces/Newsreader anywhere — the screen title 'Jun 8 – Jun 14' (24pt 700), the empty-state headline 'Your streak starts here.', and every hero numeral (daysLogged 'N of 7 days', avg kcal, protein 'Ng average', streak 'N days in a row') are sans. Design system §2.3 rules 2/3 are explicit: screen H1, big numerals, and editorial empty-state headlines MUST be Fraunces. This is the #1 reason the surface reads cheap vs Julienne's editorial register.","f":"Load Fraunces via expo-font (with Georgia iOS fallback, verified in a sim capture). Set the week-range H1 to Fraunces display-title (28-32pt 700). Render every card hero numeral (days, avg kcal, protein g, streak count, closest-to-target kcal) in Fraunces display-subtitle (~22-28pt 600). Render the empty-state headline 'Your streak starts here.' in Fraunces italic per §10.7. Keep Inter only for the eyebrows, body copy, and the day-dot labels."},{"c":"style","s":4,"i":"Cards use borderRadius: Radius.lg which resolves to 8pt in theme.ts (Radius = {sm:4, md:6, lg:8, xl:12}). Design system §4 + §6.1 specify primary cards at radius-lg = 16pt. At 8pt the cards read boxy/utilitarian, not the soft premium card language. The token name 'lg' is misleadingly mapped — what the spec calls 16pt is not available in this Radius object at all (max is xl:12).","f":"Bump card corner radius to 16pt for these primary cards (use a 16pt literal or add a Radius.xl2:16 token). At minimum move from Radius.lg(8) to Radius.xl(12). Reconcile the theme Radius scale with the design system so 'lg' = 16 as the spec intends, or document the divergence — right now the surface silently ships an off-spec radius."},{"c":"style","s":4,"i":"Cards are border-only on white with no shadow. Design system §5 + §6.1 state cards on the white base get a hairline border PLUS a soft shadow (iOS shadowColor #1B1814, opacity 0.06, radius 4, offset {0,1}, elevation 2). The flat bordered cards on flat white read like form fieldsets, contributing to the generic look. The card() helper in weekly-recap.tsx sets borderWidth/borderColor but no shadow props.","f":"Add the standard card shadow to the card() helper: shadowColor '#1B1814', shadowOpacity 0.06, shadowRadius 4, shadowOffset {width:0,height:1}, elevation 2. Apply to all primary cards on this surface."},{"c":"spacing","s":3,"i":"Off-scale literals violate the 4pt grid. Header eyebrow uses marginBottom: 6 (off-scale; should be 8/sm). Day-dot grid uses gap: 8 (sm — fine) but inner dot-to-label gap: 6 (off-scale) and marginTop: Spacing.xs(4). Freeze line marginTop uses Spacing.sm(8) — OK. The 6pt values are the offenders and appear in the header and the most-scrutinised day-dot row.","f":"Replace marginBottom: 6 on the header eyebrow with Spacing.sm (8). Replace the day-dot inner gap: 6 with Spacing.xs (4) or Spacing.sm (8) — pick one and apply consistently. Audit the file for every raw numeric spacing literal and snap to the Spacing token set."},{"c":"spacing","s":3,"i":"Horizontal screen padding is paddingHorizontal: Spacing.xl (24pt). Design system §3.1 sets mobile screen-edge margin to 16pt (xl on web is 24px, but mobile is 16). At 24pt the cards are unusually narrow and the content column reads pinched/loose against the white field vs the 16pt convention used elsewhere in the app.","f":"Change contentContainerStyle paddingHorizontal from Spacing.xl (24) to Spacing.md (16) to match the canonical mobile screen-edge and the rest of the app's surfaces. Verify against Today/Progress horizontal margins for consistency."},{"c":"spacing","s":2,"i":"Inter-card gap is marginBottom: Spacing.md (16) inside the card() helper, but the design system §3.1 puts between-card-sections at 2xl (24/32). The recap reads as a tight stack of equal-weight cards with no breathing room or sectioning rhythm, reinforcing the undifferentiated card-stack weakness the spec calls out in §2 of progress-insights.md.","f":"Increase inter-card spacing to Spacing.xl (24) and add a Spacing.xxl (32) gap between the check-in block and the rollup cards to establish hierarchy. Consider a hairline section eyebrow grouping (e.g. THIS WEEK) above the rollups."},{"c":"style","s":3,"i":"The 'Start streak' pip in the header (StreakPip at days=0/inactive) renders as a muted grey chip with a flame glyph and reads like a disabled/placeholder button rather than a premium element. On a near-empty screen it is the most prominent interactive-looking object and it looks dead. The inactive tone (colors.cardBorder bg, textSecondary fg) gives it a low-confidence appearance.","f":"For the recap header context, either suppress the pip entirely at 0 days (the empty card already explains the streak) or restyle the inactive pip with the brand soft tint (Accent.primarySoft) + plum ink so it reads as a calm informational badge, not a greyed-out CTA. Confirm against the calm-streak posture in the file header comment."},{"c":"typography","s":2,"i":"Section eyebrows use letterSpacing: 0.88 at 11pt 700 with color textTertiary. Design system §2.2 section-eyebrow is Inter 10-11pt 600, +0.08em tracking, colour --secondary (sage). 0.88 absolute is roughly right for 11pt but the weight (700 vs 600) and the colour (textTertiary vs sage --secondary) diverge, and the value is a magic number rather than a computed +0.08em token.","f":"Standardise the eyebrow to Inter 11pt 600, letterSpacing computed as 11*0.08≈0.88 (document it), colour --secondary (sage #7C8466) per the eyebrow spec. Extract a shared SectionEyebrow component so Today/Progress/Recap all share one definition rather than re-deriving it inline."},{"c":"parity","s":2,"i":"No /weekly-recap route exists on web — the dedicated recap surface is mobile-only. The check-in (TDEE delta + why-line + Adjust-goal-pace) is mirrored inside the Progress <Digest> card on web (src/app/components/suppr/digest.tsx accepts a weeklyCheckin payload), but the standalone day-dot grid, closest-to-target card, and streak/freeze ledger of THIS screen have no web equivalent. Documented as intentional in the file header, but it is a genuine cross-platform divergence that should be tracked, not silently accepted.","f":"Confirm the carve-out is logged (it reads as intentional per the file comment + the StreakPip web-deferral note). If so, ensure a Linear ticket tracks bringing the recap rollups (day grid, closest-to-target, streak ledger) to the web Progress surface so iOS-leads-web parity is an explicit roadmap item, not a permanent gap. Per CLAUDE.md no-silent-deferrals, the web-pip/web-recap deferral needs an ENG reference."},{"c":"functionality","s":3,"i":"Empty/loading/error states are functionally complete and correctly toned, BUT the empty state renders inside a full bordered card. Design system §6.3 + §10.7 say empty states get NO card chrome — full-width editorial prompt (Fraunces italic headline + Inter body + optional terracotta/plum CTA). The current empty card with sans headline contradicts the empty-state pattern and is part of why the screen reads generic.","f":"Render the empty state without card chrome: Fraunces italic headline 'Your streak starts here.', Inter body beneath, and a plum text-link CTA 'Log a meal' routing to Today (?openLog=1). Drop the bordered card wrapper for the empty branch only."},{"c":"photography","s":1,"i":"No imagery anywhere on the surface — which is largely correct for a data/recap screen (the design system does not mandate photography here). However the empty state is a cold all-text card with no warm fallback or visual anchor; §10.7 empty states allow a small sage lucide icon, and the spec elsewhere uses warm gradient/illustration anchors for empty surfaces. The current empty state is visually barren.","f":"Add a single small sage lucide icon (e.g. CalendarDays or Flame at 24-32pt, sage) above the empty-state headline per §10.7 step 1, to give the otherwise-empty viewport a warm focal point. No FLUX photography needed on this analytical surface."}]},{"name":"whats-new","model":"sonnet","impl":"apps/mobile/app/whats-new.tsx","gaps":[{"c":"functionality","s":5,"i":"Release date renders ONE DAY EARLY. Capture shows '11 May 2026' but the entry's releaseDate is '2026-05-12'. `new Date('2026-05-12')` parses as UTC midnight, then toLocaleDateString renders in the device's local TZ — on any timezone west of UTC it shifts back a day (reproduced: TZ=America/Los_Angeles → '11 May 2026'). Shipping a wrong release date on the 'what's new' surface is a credibility hit on a premium app.","f":"Parse as a local calendar date, not UTC. In formatReleaseDate, split the ISO ('2026-05-12'.split('-')) and build `new Date(y, m-1, d)`, or append a time without Z. Identical bug + fix exists in app/whats-new/page.tsx (web) — fix both in the same commit. Add a TZ-pinned unit test (the CLAUDE.md date-dependent-test note applies)."},{"c":"typography","s":4,"i":"No serif anywhere. The build label 'Build 49 (1.0.7 #49)' is Inter 20pt/700 (buildTitle) and the nav title 'What's new' is the default iOS system sans title. Design system §2.3 mandates Fraunces for screen titles and for any number that is the focus of a card (the build label is an achievement-grade headline → display-section/subtitle, Fraunces 17-22pt 600). The whole screen is sans — it loses the 'editorial cookbook' register that is the entire premium thesis.","f":"Set buildTitle to Fraunces (fontFamily serif token), ~20-22pt weight 600. Set the native-stack headerTitle to a Fraunces Text component (headerTitle render prop) so the nav bar reads editorial. Verify the font actually loaded in a fresh sim capture (system serif fallback is Georgia — design system §2.1)."},{"c":"spacing","s":4,"i":"Multiple off-scale values in the row primitive. itemRow uses `paddingVertical: 12` and `gap: 10` (between bullet and text); the release headline uses `marginTop: 6`; sectionHeading uses `marginBottom: 8` raw. The canonical Spacing scale (constants/theme.ts) is 4/8/16/20/24/32/40 — 12, 10 and 6 are NOT on it. The 12pt row padding is the most visible: rows read slightly cramped vs the 16pt card-padding rhythm used by headerCard.","f":"paddingVertical: 12 → Spacing.md (16) for breathing room, or Spacing.sm (8)+ if you want denser — pick one on-scale. gap: 10 → Spacing.sm (8). marginTop: 6 (release headline) → Spacing.xs (4). marginBottom: 8 → Spacing.sm. Replace every raw literal with a Spacing token so the screen passes the spacing lens."},{"c":"parity","s":4,"i":"Mobile shows ONLY the latest build's entry; web (app/whats-new/page.tsx) renders ALL releases as a scrolling timeline with per-release headers, a 'Latest' chip, and an RSS subscribe link. Same SSOT, fundamentally different information architecture. A user who taps the same link on each platform sees a single card on iOS and a full release history on web.","f":"Decide the canonical IA and apply to both. Recommended: mobile maps the same getAllChangelogs() timeline (it already imports getLatestChangelog only). Either add the timeline to mobile or trim web to latest-only — but they must agree. Update the mobile file's own header comment which claims the surfaces 'render the exact same entry' (no longer true)."},{"c":"style","s":3,"i":"Kind is not differentiated on mobile. NEW / FIXED / COMING SOON all use the same plum bullet (accent.primary) and the same plain uppercase Inter heading, so the only signal separating sections is the heading text. Web colour-codes each kind (emerald/sky/amber chips + matching bullets) giving far stronger scannable hierarchy. Mobile hierarchy reads flat.","f":"Differentiate the three kinds on mobile — at minimum a kind chip (like web's) using the LOCKED in-app semantic palette: NEW → success sage, FIXED → a neutral/info treatment, COMING SOON → amber (§1.2). Keep bullets a single accent if you prefer restraint, but the section label should carry a coloured chip, not bare uppercase text. (Do NOT copy web's raw emerald/sky/amber Tailwind — map to the in-app tokens.)"},{"c":"style","s":3,"i":"The screen is a flat bordered list with no depth or editorial chrome — generic iOS-changelog feel, not Sloe. headerCard and sectionCard are warm cards (good) but carry only a 1px border and no shadow; the design system §5 specifies a hairline border PLUS a soft shadow (0 1px 4px rgba(27,24,20,0.06) / iOS shadowOpacity 0.06) for cards on the white base. Without the shadow the cards sit dead-flat on the page.","f":"Add the standard card shadow (shadowColor #1B1814, shadowOpacity 0.06, shadowRadius 4, shadowOffset {0,1}, elevation 2) to headerCard and sectionCard. Consider a subtle Fraunces serif build-label + a thin accent rule under the header to lift it above 'system list'."},{"c":"photography","s":2,"i":"Zero imagery. The surface is text-only. The design system imagery rules (§11) and the editorial-cookbook thesis mean a premium 'what's new' could carry a small warm editorial header treatment (e.g. a hairline-framed monogram or a muted dish/ingredient motif) to feel like Sloe rather than a plist dump. Currently it's indistinguishable from any utilitarian app's changelog.","f":"Add a restrained brand/editorial element to the header card — a small Sloe mark or a single muted ingredient single-subject (§11.1 pipeline) — OR accept text-only as an intentional, documented choice and note it so it doesn't read as an omission. Recommend the former for premium parity; do not leave it cold/empty."},{"c":"parity","s":2,"i":"Web background is a slate-50→white→slate-50 gradient (`bg-gradient-to-br from-slate-50 via-white to-slate-50`), violating design system §0 constraint 1 (white base #FFFFFF everywhere in-app; no page wash). Mobile correctly uses colors.background (white). The two grounds diverge and web breaks the locked white-base rule. (Flagging as ground/structure, not accent direction.)","f":"Web: drop the slate gradient wrapper, use white base (bg-white / --background) to match mobile and §0. Keep dark-mode handling via the documented token, not a hardcoded slate gradient."},{"c":"typography","s":2,"i":"Section heading letterSpacing is a raw 1.1 with textTransform uppercase at 12pt/700. The design system section-eyebrow spec is Inter 10-11pt, weight 600, letter-spacing +0.08em, sage colour. 12pt/700/1.1px is heavier and tighter than the eyebrow token — slightly off-ramp.","f":"Align sectionHeading to the section-eyebrow token: ~11pt, weight 600, letterSpacing ≈0.9 (0.08em of 11pt), colour textSecondary (sage). Minor, but it's the one eyebrow on the screen and should match the ramp exactly."},{"c":"style","s":1,"i":"Bullet dots are 6×6pt plum filled circles at marginTop 7 — fine, but with the long multi-line item text (15pt/21 line-height) and 12pt row padding, the dot-to-text relationship and the flat divider list make long entries (e.g. the multi-sentence 'Weight chart on Progress…') hard to scan. Reads as a wall of bullets rather than a curated set of upgrades.","f":"Once kind chips + on-scale padding land, this largely resolves. Optionally tighten itemText lineHeight to the body-primary token (15pt → ~22) and keep the bullet aligned to the first line cap-height (marginTop on-scale, e.g. 6→ derive from line-height rather than a magic 7)."}]},{"name":"today","model":"opus","impl":"apps/mobile/app/(tabs)/index.tsx + apps/mobile/components/today/*","gaps":[{"c":"style","s":5,"i":"Empty calorie ring is a single flat frost-mist (#EDEAF1) track on the #F6F5F2 card — the two tones sit only ~10 luminance apart, so the ring's defining element is nearly invisible on a cold open. The largest object on the screen reads as an unfinished placeholder, not a premium hero. This is the dominant first-impression failure.","f":"On the empty state, lift the track contrast: either darken the empty track to the Sloe borderStrong (#C9C2D6) or render a subtle plum→frost gradient arc (the brand AccentWinGradient soft stops) so the ring shape is unmistakable. Pair with a hairline or 1px inner ring so the circle reads as intentional geometry, not a faint outline. Keep 'Start your day / 1,252 kcal goal' centred."},{"c":"style","s":4,"i":"Week strip active day (today = '9') has no real selected affordance — only a 4px dot under the number (DayStrip dotKind 'minimal'). The selected/today number is not tinted plum/clay and carries no pill or underline, so the strip reads as a cold, undifferentiated row of grey numerals. No best-in-class date strip leaves the current day visually identical to the other six.","f":"Give the active day a clear treatment per the design-system selected-state rule: tint the '9' numeral to plum (MacroColors.calories) at full weight and/or wrap it in a soft plum pill (Accent.primarySoft, radius-full). Keep the dot for 'has logs' but make day-selection legible without it."},{"c":"spacing","s":3,"i":"macroTileGridGap is 12 (constants/layout.ts) — off the mobile Spacing scale (xs4·sm8·md16·lg20·xl24). The Figma/design-system between-tile grid gap is md (16). 12 is a legacy v49-density carryover and breaks the 4pt rhythm against the rest of the screen.","f":"Set macroTileGridGap to Spacing.md (16) to match the design-system 'between-tile gap in grids = md' rule, or Spacing.sm (8) if a tighter grid is intended — but not a bare 12. Re-verify the 48%/48% tile widths still fit with the new gap."},{"c":"spacing","s":2,"i":"todayScrollGap (8) and planScrollGap (10) are hand-tuned Layout constants; 10 in particular is fully off the 4pt scale. The 8/32 hero-cluster vs section-break split is documented but the 10 and the 12 grid gap mean three different non-scale gaps coexist on one screen.","f":"Normalise the custom Layout gaps onto the Spacing scale: todayScrollGap → Spacing.sm (8, already on-scale), planScrollGap → Spacing.sm (8) or md (16), and remove the bespoke 10/12 so every gap on Today is a Spacing token. Keep todaySectionBreak=32 (Spacing.xxl, on-scale)."},{"c":"functionality","s":3,"i":"Macro tiles drop the spec'd per-tile caption. today.md §3.3 and §4 require 'X g remaining' (success) / 'X g over' (amber) under each tile; the shipped TodayDashboardMacroTiles renders only value, '/ target', and a bar — no remaining/over line. The user loses the at-a-glance 'how much left' read that the spec calls the warm-coaching payoff, and over-budget macros have no amber text signal (only the bar, which never flips colour by design).","f":"Add the caption row beneath the bar: 'N g remaining' in Accent.success when current<target, 'N g over' in Accent.warningSolid (amber, AA-safe as text) when over — per the locked macro over-budget rule. For referenceOnly macros (sugar/sodium) keep the muted 'ref' treatment, no remaining claim."},{"c":"typography","s":2,"i":"On an empty account the serif '0g' macro values (Type.title 20px Newsreader) are the heaviest typographic element in the lower fold and read as a row of zeros — the editorial serif numeral, which is meant to celebrate a real achievement number, instead amplifies emptiness. Hierarchy inverts: the empty hero ring is faint while four serif zeros shout.","f":"Soften the zero state: render '0' (or '—') at textTertiary/muted, or de-weight the value colour until current>0, so the serif numeral earns its weight only when there is data. Pairs with the empty-ring lift fix to rebalance the cold-open hierarchy."},{"c":"parity","s":3,"i":"Web hero ring (src/app/components/suppr/today-hero-ring.tsx) renders an extra visible text button 'Show macro rings / Hide macro rings' (MACRO_RING_TOGGLE) below the ring; mobile (TodayHeroRing) has no equivalent — macro-ring expand is long-press only. The two surfaces present a different control set for the same feature, an undocumented divergence.","f":"Decide one pattern and ship it both places: either add the same labelled toggle on mobile (it also satisfies today.md §3.2 / §2 accessibility — long-press needs a tap-accessible equivalent), or remove it from web for parity. Given the spec's accessibility requirement, adding the visible toggle to mobile is the correct direction."},{"c":"parity","s":2,"i":"Under-ring forward coach line ('Room for {meal}…' / 'About N kcal left… No rush.') is mobile-only — TodayDeficitInsight has no web render even though the copy + nextUnloggedMealSlot helpers already live in @suppr/shared/copy/today. today.md §6 documents this as an intentional carve-out, but the capture's coach line is one of the most premium warm-coaching touches on Today and web Today shows nothing equivalent.","f":"Track it explicitly rather than leaving it as a silent carve-out: it is documented in today.md §6.3 so it is not drift, but the shared helpers mean web can adopt the identical line cheaply. Confirm the carve-out is still intended or add the web render at Today parity; do not reimplement copy/slot logic — import the shared helpers."},{"c":"functionality","s":2,"i":"Empty meal slots show no guidance. today.md §3.4 specs Lifesum-style 'Recommended for {slot}: ~N kcal' on empty slots for users with logging history (a calm nudge, never a block). The shipped meals section is silent on empty slots — a missed warm-coaching moment that the 'permission not restriction' positioning calls for. (Not visible in this empty capture but confirmed against the meals section spec checklist.)","f":"Add the spec'd empty-slot guidance line (text-xs sans, muted sage) derived from target × typical meal distribution (breakfast 25% / lunch 35% / dinner 30% / snacks 10%), suppressed on first-ever use. Behind the redesign flag per the visual-change rule."},{"c":"style","s":3,"i":"Ring card uses lift='flat' (Elevation.card no-op) so the hero sits with zero elevation on the page; the design-system default resting card is now cardSoft (the 0.16/18px plum penumbra Grace explicitly tuned because 'cards blend into the background'). The hero — the single most important card — is the one that should read most lifted, yet it is explicitly flat, which on the near-tonal #F6F5F2-on-#FFFFFF pairing makes the whole top of the screen read as one undifferentiated slab.","f":"Re-evaluate lift='flat' on the hero: either move it to lift='soft' (cardSoft) so it separates from the page like every other resting card, or confirm flat is deliberate for the hero only and document why. Given Grace's 'sim cards blending' note, soft is the likely correct default."},{"c":"photography","s":1,"i":"No Sloe FLUX imagery anywhere on the visible cold-open. This is correct for an empty account (north-star photo hero is empty-day-below-meals and the meals are empty), so it is not a bug — but it means the premium editorial-photography differentiator (the spec's stated viral/retention surface, today.md §3.5) is entirely absent from the first screen a returning user sees, leaving the cold-open feeling like a pure tracker.","f":"No fix on this capture (judging chrome on an empty account). Verify on a populated account that the north-star card renders the hyperreal @thelittleplantation-style dish photo with the warm gradient/monogram fallback hierarchy, never a flat/placeholder tile."}]},{"name":"library","model":"sonnet","impl":"apps/mobile/app/(tabs)/library.tsx + apps/mobile/components/nutrition/MacroIconRow.tsx","gaps":[{"c":"functionality","s":5,"i":"STALE CAPTURE — the rendered card does not match HEAD. The PNG shows a 2-line macro block (line 1 '312 kcal · 55g protein', line 2 '4g · 8g', then '4 servings') with an OLD icon set (flame / meat-drumstick / fork-knife / wheat). HEAD's working tree (uncommitted: library.tsx +93, MacroIconRow.tsx +16) renders a SINGLE wrapping MacroIconRow with showMacroLetters=false, emphasiseProtein (heavier ink protein), Dumbbell protein icon, plus a separate '★ saves · N min' meta row that falls back to servings. The dev client was not reloaded against the working tree, so every card-level finding from this pixel is unverifiable. This is the documented stale-dev-client-bundle trap.","f":"Reload the dev client against the current working tree (terminate + relaunch — Fast Refresh is not enough after StyleSheet/module changes) and re-capture library.png before drawing any card-level conclusions; the harness should hard-fail when bundle != HEAD (ENG-769). Re-audit the card from the fresh capture."},{"c":"photography","s":4,"i":"Bottom-right card is a COLD empty cream tile — a faint sage fork/spoon RecipeHeroFallback glyph on flat cream, with a bookmark dot but no title/photo above the fold. Next to two warm editorial dish photos it reads as a broken/loading card, not an intentional fallback. §11.4 wants sage→cream gradient + cuisine glyph, but at this size on a near-empty account it still undersells vs Julienne's all-photo gallery.","f":"Confirm RecipeHeroFallback renders the sage→cream GRADIENT (not flat cream) at card size and the cuisine glyph is sized/centred to read as deliberate. For seed/curated recipes ensure a real FLUX editorial photo is generated so the gallery is photo-dense; reserve the fallback for genuinely image-less user imports."},{"c":"spacing","s":3,"i":"Off-scale paddings throughout the header chrome. filterPill: paddingHorizontal 13, borderRadius 20 (both off the Spacing 4/8/16/20/24 and Radius 4/6/8/12 ladders). searchInputWrap: gap 10, paddingHorizontal 14, paddingVertical 14 (10 and 14 off-scale). quietControl: paddingHorizontal 10, paddingVertical 5 (10 and 5 off-scale). planImportPill: paddingHorizontal 11, paddingVertical 6 (11 off-scale).","f":"Snap to the canonical scale: filterPill -> paddingHorizontal 12, radius Radius.full; searchInputWrap -> gap 8, padding 16 (Spacing.md), radius 12; quietControl -> paddingHorizontal 8, paddingVertical 4; planImportPill -> paddingHorizontal 12, paddingVertical 4. Re-derive these on-scale instead of carrying the 13/14/11/5/20 magic numbers left by historical tester fixes."},{"c":"typography","s":2,"i":"Fractional / off-ramp font sizes on the card. macroValue fontSize 11.5 (no 11.5 in the ramp; caption is 11-12); MacroIconRow Chunk hardcodes fontSize 12 inline. Card title is Newsreader_500Medium 15pt — recipes.md §0 'title' role and the cross-cutting DS §2 treat recipe names as an editorial moment, so 500/15 sits at the light end and slightly undersells the editorial register vs Julienne.","f":"Replace 11.5 with a ramp token (12pt caption) and route Chunk's inline 12 through the same caption token. Consider bumping the card title to Newsreader/Fraunces 600 at 15-16pt for more editorial weight while keeping the 2-line clamp."},{"c":"parity","s":3,"i":"Web and iOS Library cards have diverged. iOS uses the shared MacroIconRow (icon+value chunks, single wrapping row). Web mobile-grid hand-rolls its own macro span row (raw 11.5px text, gap-x-2/gap-y-0.5) instead of the RN gap:10 rhythm. Web DESKTOP grid is an entirely different card (4:3 hero, kind badge Saved/Your recipe/Imported, kcal-pill overlay, fit-% pill, 'Create your own version' button) with NO iOS equivalent — iOS has no fit-% pill and no kind badge.","f":"Pick one canonical mobile card and make web's mobile-grid consume the same macro primitive (port MacroIconRow or a shared macro-chip-row to web) so gap/size/weight match. Reconcile the desktop-only fit-% pill + kind badge + 'Create your own version' against iOS — add to iOS or document as an explicit desktop carve-out; today it is silent drift."},{"c":"functionality","s":2,"i":"Header reads 'Recipes' (section chrome) with Library/Discover sub-tabs, but recipes.md §3.1 IA specifies a possessive 'Your Recipes' editorial header for Library ('this is your collection, not a database'). The personal-possessive premium framing is absent; the surface reads as a generic section, not a personal cookbook.","f":"Either adopt 'Your Recipes' for the Library tab title, or explicitly reconcile recipes.md §3.1 with the deliberate RecipesTabChrome constant-'Recipes' decision so it stops reading as an unmet requirement."},{"c":"functionality","s":2,"i":"Sort is a blind CYCLE. The count-line 'Recent' chip cycles Recent->Calories->Protein on each tap with no menu — recipes.md §2.1 flags this exact weakness and §3.1 calls for a 'Sort: {label}' chip opening a 3-option action sheet. The chip shows the current label (good) but tapping silently re-cycles, so reaching 'Protein' from 'Recent' requires guessing the order.","f":"Replace cycleSort with an action-sheet picker (Recent / Most calories / Most protein) per §3.1, keeping the current-sort label on the chip. Mirror on web (cycleSort) for parity."},{"c":"spacing","s":2,"i":"Card body vertical rhythm is uneven: cardBody gap 4 plus per-child overrides macroRow marginTop 2 and metaRow marginTop 4, so title->macro->meta spacing stacks inconsistently rather than on one rhythm.","f":"Use a single consistent vertical gap on cardBody (gap: Spacing.xs = 4) and drop the marginTop 2/4 child overrides so title, macro row, and meta row sit on a uniform 4pt rhythm; verify in a fresh capture."},{"c":"style","s":2,"i":"Category pills, count-line quiet controls, and the search field all share a near-identical cream/transparent + hairline treatment, so the filter row reads flat / low-hierarchy on white. The selected pill's soft aubergine tint fill + aubergine ink (Sloe §7) is calm but low-contrast at small size and easy to miss vs Julienne's clearer active filter.","f":"Verify the active category pill's aubergine-soft fill clears 3:1 on white and reads distinctly from inactive pills in a fresh capture; if subtle, give the active pill a primarySolid hairline border so the current filter is unmistakable."},{"c":"style","s":1,"i":"Library auto-redirects to Discover at savedCount=0 (useFocusEffect router.replace), so on a near-empty account the polished dashed-cream emptySlab (frost-mist badge, serif heading, stacked CTAs) is effectively unreachable in the default flow — the only first impression is Discover, and the empty-state polish is invisible.","f":"Confirm ENG-100 redirect is still intended; if so, document the emptySlab as a fallback-only state (deep-link/cold-open edge) or prune the redundant branch so the polish effort isn't dead code."}]},{"name":"discover","model":"sonnet","impl":"apps/mobile/app/(tabs)/discover.tsx","gaps":[{"c":"typography","s":5,"i":"The recipe-card title 'Classic Greek Salad' renders in Inter sans (discover.tsx line 463: `{ ...Type.body, fontWeight: '700' }` = Inter 14pt). This violates the single most load-bearing typographic rule in the locked design system (§2.3 rule 2: 'Meal names and recipe names ALWAYS Fraunces throughout the product') and recipes.md §3.1 which specifies Fraunces 17pt bold for card titles. A sans recipe name is the clearest tell that this is below the Julienne editorial bar.","f":"Render the hero-card title with the serif face — replace `{ ...Type.body, fontWeight: '700' }` with `Type.headline` (Newsreader serifMedium 17pt) or a dedicated serif title token at ~17–18pt. Apply the same serif to the 'More ideas' row titles (line 576, currently `Type.body`). Verify in a fresh sim capture that Newsreader actually loaded (system serif fallback is a known trap)."},{"c":"typography","s":4,"i":"Section headers 'Recipe ideas' / 'More ideas' / 'My Library' all use `Type.headline` = serif 17pt/22lh. At 17pt they read as weak, almost caption-weight dividers in the capture — they do not carry the editorial section-divider weight the spec wants. Design system §2.2 puts section heroes at display-subtitle (22–28pt) and recipes.md §0 puts section titles at 20–22pt serif `title`. The screen also has no serif H1 on the Discover canvas itself (the 'Recipes' chrome title is separate).","f":"Promote the three section headers to a serif 20–22pt weight (`Type.title` at 24pt is one step too far; introduce/borrow a 20–22pt serif section token, or use `Type.headline` at a bumped size). Give them more presence than a recipe row label so the eye parses 'Recipe ideas' as a section break, not a line of body copy."},{"c":"spacing","s":4,"i":"Multiple off-scale spacing values against the mobile Spacing ladder (xs:4 sm:8 md:16 lg:20 xl:24 xxl:32 xxxl:40). Hero-card vertical gap is `gap: 12` (lines 936, 957) — 12 is NOT a mobile token (it is the *web* md, but the mobile scale jumps 8→16). Hero card body padding `padding: 14` (line 452), import-CTA `padding: 14` + `gap: 12` (lines 819-826), search bar `paddingHorizontal/Vertical: 14` (lines 617-618), pills `paddingHorizontal: 13` (lines 678/711), 'More ideas' rows `gap: 12, padding: 12` (lines 552-553). The screen is built almost entirely on 12/13/14 — none of which are on the mobile scale.","f":"Snap every value to the mobile Spacing scale: card gap 12→16 (Spacing.md); card/CTA/search padding 14→16 (Spacing.md); 'More ideas' row padding 12→16; pill paddingHorizontal 13→12 or define a deliberate chip token (note theme.ts comment claims 13/8 is 'canonical' for descender clearance — if kept, document it as an intentional chip carve-out per no-silent-deferrals, otherwise it reads as drift). The 12px values are likely web tokens leaking into mobile."},{"c":"parity","s":4,"i":"Web DiscoverFeed.tsx has structurally diverged from this iOS surface. (1) Web renders a `<h1>Discover</h1>` (sans extrabold 24px, line 420) — mobile has NO 'Discover' H1; it uses RecipesTabChrome with a serif 'Recipes' title + Library/Discover sub-tabs. Different IA. (2) Web section headers 'Recipe ideas'/'More ideas' are caps eyebrow labels (`text-[13px] font-extrabold uppercase tracking-[0.04em] text-muted-foreground`, lines 847/940) — mobile renders them as 17pt serif headlines. Two different treatments for the same header. (3) Web hero cards use full-bleed image with WHITE OVERLAY title text + drop-shadow (lines 883, 653); mobile uses below-image cream card with ink title (the 2026-05-22 'everything should be like the bottom one' consolidation). Web never adopted that consolidation.","f":"Reconcile the two surfaces (memory rule: mobile design decisions apply to web in the same commit). Decide one canonical pattern per element — almost certainly: drop the web overlay-title hero in favour of the below-image cream card to match mobile's consolidated grammar; align section-header treatment (pick serif headline OR caps eyebrow on BOTH); and reconcile the 'Discover' H1 vs 'Recipes' chrome-title IA. Gate behind a flag per the visual-change rule."},{"c":"style","s":3,"i":"The category pill row in the capture shows 'Following · All · Trending · Quick 30 · Under 500 cal'. Selected pill is a soft aubergine tint (treatment §7), which is correct, but in the capture 'All' reads as the only selected pill while the others are transparent with a hairline border — the inactive pills sit on a fully transparent background so they read as slightly floating/unanchored against the white page, and the row's relationship to the search field above and 'Recipe ideas' below is loose. Pill labels also use `Type.caption` (11pt) which is light for a primary filter control.","f":"Tighten the filter row's vertical rhythm to the section above/below (consistent Spacing.md), and consider bumping pill label to `Type.label`/13pt for a more deliberate control. Confirm the inactive pill border colour (`colors.cardBorder`) is visible enough on white to read as a pill, not a ghost."},{"c":"style","s":2,"i":"The hero macro row renders '380 kcal · 13g · 18g · 28g · 5g' with icon glyphs. The macro letters/units are present but the row is dense and every value reads at near-equal weight despite `emphasiseProtein` being passed — in the capture the protein emphasis (heavier ink on 13g) is subtle and easy to miss. recipes.md §3.1 wants protein to be the one clear visual accent ('this is a tracker, not just a recipe app').","f":"Strengthen the protein emphasis so it is unmistakably the accented value — e.g. heavier weight + full ink + slightly larger icon/dot, per MacroIconRow's `emphasiseProtein` contract. Verify the difference is legible at card scale in a capture, not just in code."},{"c":"functionality","s":2,"i":"The import CTA copy reads 'Import from TikTok, Instagram...' with the trailing ellipsis truncating mid-sentence by design (line 833), and the subtitle 'Paste a link or share from any app'. The truncated brand list reads slightly unfinished/placeholder-ish rather than intentional. Functionally the CTA is correctly wired (routes to /import-shared, testID present) — this is a polish nit, not a break.","f":"Either complete the brand list ('TikTok, Instagram & YouTube') or rephrase to avoid the dangling ellipsis ('Import from a link or social post'). Keep the testID and route unchanged."},{"c":"photography","s":1,"i":"Photography is on-spec and a genuine strength: the Greek Salad hero is a real editorial-style finished-dish photo (overhead plated salad, warm tones), matching imagery system §11.2. No cold/empty/placeholder tiles are visible in this capture. The only forward risk is the below-fold cards and the warm RecipeHeroFallback path, which are wired correctly (sage→cream fallback per §11.4) but not exercised by this populated capture.","f":"No fix needed for the visible hero. Confirm in a multi-card capture (and an image-less recipe) that the RecipeHeroFallback tile renders the warm sage→cream treatment and never the pale-lilac border base, per the 2026-06-08 conformance note in recipes.md."}]},{"name":"progress","model":"opus","impl":"apps/mobile/app/(tabs)/progress.tsx + apps/mobile/components/progress/*","gaps":[{"c":"functionality","s":5,"i":"Contradictory data on AVERAGE ADHERENCE: headline reads 109% calorie adherence but all 7 on-target streak dots top-right render empty/grey. On-target = calories>0 AND calories<=effectiveTarget; a 109% AVERAGE adherence with zero on-target days is internally inconsistent and reads as broken/placeholder chrome on this account. The dots compute from weekStats.days (this-week, calendar) while the % is range-scoped (30d) — two different windows shown as one story.","f":"Either source the streak dots from the SAME range window as the headline % (use macroRange/caloriesRange per-day booleans, not weekStats.days), or suppress the dot row entirely when onTargetDays.filter(Boolean).length === 0 (mirror the ProgressOnTargetRibbon's 'don't show an empty achievement' rule). Empty grey dots next to a 109% headline is the single most premium-damaging thing on the surface."},{"c":"style","s":4,"i":"ProgressStoryGate ring (THIS WEEK card, top-right) is nearly invisible — at 0/3 logged the 24pt single-stroke arc shows only a faint grey track with no clay fill, so it reads as an empty/dead circle rather than a progress affordance. Against editorial-luxury (Julienne) this is a cold, unexplained dot.","f":"Give the ring a minimum visible clay arc floor (e.g. clamp ringFraction to >=0.06 so even 0/3 shows a small clay tick), or replace the bare ring at 0 days with the explicit '0 / 3' numeral inside the ring (the spec §3.2 wants 'days until your first story' under the ring). Right now the ringLabel '0 / 3 days logged · 3 needed to unlock' is below the headline but the ring itself communicates nothing."},{"c":"functionality","s":4,"i":"Above-fold weight chart (54.6 kg + Trend/Scale) is context-free in the first viewport: bare clay polyline with no Y-axis ticks, no visible goal-line label, no stat-pair delta beside the big kg numeral. The spec §3.4/§7.1 mandates a stat-pair header (avg + signed delta toward/away from goal) and a pinned 'GOAL {value}' pill. The 'Goal {value} · on track for ~{date}' line and START/CURRENT/GOAL/RATE row exist but sit below the chart, off the first screen. MacroFactor/Zero parity bar wants the interpretation ABOVE the line.","f":"Surface the week-delta (↓ −0.6 kg this week) inline beside the 54.6 kg numeral (the code already computes weekDeltaKg and renders the TrendingDown row — confirm it shows; on this empty-ish account it's suppressed by the 0.05 threshold). Add the dashed goal-line label pill on the sparkline (currently a label-less dashed line at t.sub 0.5 opacity — invisible). Add 2 quiet Y-axis end-labels (min/max kg) so the line has scale."},{"c":"spacing","s":3,"i":"Pervasive off-scale internal spacing against the canonical mobile Spacing token (xs:4 sm:8 md:16 lg:20 xl:24 — note 12 and 6 and 14 are NOT on the scale). Concrete offenders: range-picker gap:6 (→8) and skeleton gap:6; weight-card header gap:12, sparkline marginTop:12, stat-row marginTop:12/paddingTop:12, log-button marginTop:14, view-all marginTop:10; daily-calories legend marginTop:12; AVERAGE ADHERENCE streak-dots gap:6; ProgressStoryGate eyebrow marginBottom:6; energy-triad value marginTop:6. These read as a hand-tuned cascade, not a system — exactly the cadence inconsistency the spec flags.","f":"Snap every raw 6→Spacing.sm(8), 12→Spacing.md(16) or sm(8) where 16 is too loose, 14→Spacing.md(16), 10→Spacing.sm(8). The ProgressAverageAdherence card already did this snap under ENG-996 (Spacing.sm/lg/md) — extend the same discipline to the weight card, range picker gap, energy triad, daily-calories, and StoryGate. The 6px gaps in particular read visibly tight."},{"c":"spacing","s":2,"i":"Range-picker pill gap (6px) is tighter than the card-to-card rhythm (Spacing.lg=20 via progressScrollStyle.gap) and tighter than the 8px the pills want, making the 7d/30d/90d/All row feel cramped relative to the airy cards below it. The pills also use Radius.full with paddingVertical:8 only — a slightly thin tap target visually for a luxury surface.","f":"gap: Spacing.sm (8); bump pill paddingVertical to 9–10 so the pills have more presence and the active 30d soft-tint fill reads as a deliberate selected state, not a hairline."},{"c":"style","s":2,"i":"AVERAGE ADHERENCE macro bars are full-width, 8pt-tall, fully-saturated fills (Protein sage 79%, Carbs clay 104%, Fat amber 117%, Fibre teal 34%). Four heavy saturated bars stacked read busier/more 'tracker-dashboard' than editorial-luxury. The over-budget Carbs/Fat correctly go to amber with '· over', but Carbs at 104% is rendered in the macro clay AND flips to amber on over — visually Carbs (clay) and the over-amber are close in hue, muddying the over-signal.","f":"Consider a lighter bar track-to-fill contrast (the fill is fine but 8pt full-saturation x4 is heavy) or reduce bar height to 6pt per spec §7.3 (4–6pt). For the over-signal, the spec §7.3 wants an amber '!' icon + clamp-at-100 with a 3-dot overflow indicator rather than recolouring the whole bar amber — the current full-amber bar loses the macro identity. Lower priority since the · over text + colour is a legible system."},{"c":"typography","s":2,"i":"Big numerals correctly use Newsreader serif (Type.display: 109%, 54.6 kg, 24pt daily-avg) — on-bar. But the THIS WEEK headline 'Your story builds with your data' uses Type.headline (Newsreader 17pt/500) while the spec §3.2 calls the headline the most-important text at Fraunces 18pt. Minor: 17pt vs 18pt is within tolerance, but the StoryGate body is Inter 12pt/18 (styles.body) — 12pt is below the spec's 13–14pt body floor and reads small/secondary under the serif headline.","f":"Bump StoryGate body from fontSize:12 to 13 (label-secondary floor) for legibility parity with the AVERAGE ADHERENCE rows (13pt). Headline 17→18 optional. Confirm Newsreader actually loaded in the capture (it did — the serif numerals render), so no fallback-Georgia risk here."},{"c":"photography","s":1,"i":"No agreed Sloe photography (FLUX editorial / ingredient single-subjects) anywhere on this surface — which is CORRECT for Progress (it is a data/story surface, not a recipe surface). The empty-state 'Your progress will appear here' uses a BarChart3 lucide glyph in an IconBox, and the on-target ribbon uses an Award medal glyph — both line-icon, on-system. No cold/placeholder imagery. Flagging only to confirm: this is not a gap, it is the correct absence per design-system §11 (Progress is not a photography surface).","f":"No action — confirm reviewers don't 'add a hero image' to Progress. The line-icon empty state is the right editorial-restraint call. (Included for completeness of the photography lens.)"},{"c":"parity","s":3,"i":"Web mirror divergence risk: the StoryGate ring track on web uses className='text-border' (currentColor) while mobile uses colors.cardBorder — visually equivalent, fine. BUT the web ProgressStoryGate has the same near-invisible-ring-at-0 problem AND the web mirror layout (ProgressDashboard.tsx is 117KB / ~2.6k lines) is far larger than the mobile screen file — high risk that web has additional cards or a different above-fold order than the mobile Sloe 492:2 sequence (range → THIS WEEK → AVERAGE ADHERENCE → weight → triad → daily-calories → ribbon). The streak-dot data-window inconsistency (range-% vs week-dots) will reproduce identically on web since both consume the same props shape.","f":"When fixing the on-target-dots window bug and the ring-visibility floor, apply the SAME fix to web (src/app/components/suppr/progress-story-gate.tsx + progress-average-adherence.tsx) in the same commit per the mobile-decisions-apply-to-web rule. Audit ProgressDashboard.tsx above-fold card order against the mobile 492:2 sequence to confirm no divergence — the 117KB file is over the 400-line ceiling and a likely drift vector."},{"c":"style","s":2,"i":"Card elevation: cards use CARD_RADIUS=24 (radius-xl, generous and on-brand) with cardElevation hairline+soft-shadow — clean and premium. The THIS WEEK lilac-wash card (rgba(106,75,122,0.12) bg + 0.16 border) sits at Radius.lg(20) via styles.card, a 4px radius MISMATCH with its sibling cards at radius 24. Small but on a luxury surface the corner-radius inconsistency between the lilac insight card and the cream cards below it is detectable.","f":"Set ProgressStoryGate/ProgressHeadline card borderRadius to CARD_RADIUS (24) to match the AVERAGE ADHERENCE / weight / daily-calories cards, so all stacked cards share one corner radius."},{"c":"functionality","s":2,"i":"The AVERAGE ADHERENCE 'up N%' week-over-week trend chip is permanently hidden (adherenceDeltaPct is never passed by the host — documented data gap until weekly aggregates persist). This is correctly handled as 'never fabricate', but it means the top-right of the card on a real account shows ONLY the streak dots, leaving the headline % without the trend context the spec wants. Not broken, but an incomplete-feeling card vs the Figma intent.","f":"No invented data (correct). Track the weekly-aggregate persistence as the unblock (per no-silent-deferrals: this should have a Linear ID in the comment). Once the delta stream lands, wire adherenceDeltaPct so the chip fills the intended top-right slot and the streak dots aren't alone."}]},{"name":"fasting","model":"sonnet","impl":"apps/mobile/app/fasting.tsx","gaps":[{"c":"style","s":5,"i":"The landing card and RECENT FASTS card use a local styles.card with borderWidth:1 + colors.border ONLY — no Elevation.cardSoft. On the #FFFFFF page the #F6F5F2 card sits ~10 lum below white with just a hairline, so it barely lifts. This is the exact 'sim cards blending into the background, Figma does not do this' defect the rest of the app fixed by adopting cardSoft (the soft plum-tinted #221B26 @0.16 / 18r / y+6 ambient lift). Fasting was never migrated.","f":"Spread Elevation.cardSoft on the card style (or wrap in SupprCard) exactly as Today/Progress cards do — apply on an outer wrapper because RN overflow:hidden clips iOS shadows. This single change is the biggest premium lift on the surface."},{"c":"photography","s":4,"i":"The empty-state hero is a 96px cold lavender disc (colors.ringTrack #EDEAF1) with a thin line Moon glyph — a flat, frost-tinted placeholder. The design system §10.7 empty-state pattern wants Fraunces-italic editorial register and the imagery system bans 'cold/empty tiles'; competitors (Julienne, Zero) wrap the fasting cold-open in warm photography or a richer brand moment. This tile reads generic-wellness, not editorial-luxury.","f":"Replace the flat ringTrack disc with a warmer treatment: either the Sloe brand gradient (Damson→plum→lift, the empty-ring treatment §0.1) filling the disc, or a soft editorial moody-light still behind/within it. At minimum tint the disc with primarySoft plum rather than the cold #EDEAF1 frost so it ties to the accent system."},{"c":"spacing","s":3,"i":"stageChip uses paddingHorizontal:10 and gap:5 — both off the 4pt scale (should be 8/16 padding, 4 gap). landingStart CTA uses paddingHorizontal:28 (off-scale; should be 24 xl or 32 xxl). Extended badge uses paddingHorizontal:6/paddingVertical:2/borderRadius:4 (6 is off-scale). ringSub/startGoalValue marginTop:4 is fine but startGoalLabel letterSpacing:0.6 + fontSize:10 are hand-tuned off the Type ramp.","f":"Normalise to the scale: stageChip padding 8/4-or-10→keep but document, gap 5→4; CTA paddingHorizontal 28→24 (Spacing.xl); Extended badge px 6→8 (Spacing.sm), radius 4→Radius.sm(4) ok, py 2→keep as chip micro. Replace ad-hoc fontSize:10/letterSpacing:0.6 on startGoalLabel with Type.label (11pt, 0.88 tracking) for consistency."},{"c":"parity","s":3,"i":"Landing CTA copy diverges: mobile renders generic 'Start fast'; web renders 'Start {window} fast' (e.g. 'Start 16:8 fast'). Web is the stronger, more specific copy. Per the mobile-decisions-apply-to-web (and vice-versa) rule these should match — and the spec voice prefers naming the concrete window.","f":"Make mobile CTA label `Start ${fastingWindowLabel(fastingWindow)} fast` to match web (the accessibilityLabel already says this). Keep the Maestro regex intact."},{"c":"parity","s":3,"i":"RECENT FASTS rows diverge between platforms. Web shows a goal denominator ('12h 30m / 16h') giving context; mobile shows only the raw duration ('0h 0m') with no goal reference. Mobile also slices last 7 (slice(-7)) while web slices last 5 (slice(-5)). Both the denominator context and the row count differ.","f":"Add the '/ {goalHours}h' denominator to the mobile history row to match web (gives the otherwise-bare '0h 0m' rows meaning). Align the slice count (pick 5 or 7 and use it on both)."},{"c":"functionality","s":2,"i":"Both visible RECENT FASTS rows read '0h 0m' (zero-duration completed sessions from the empty test account). The chrome handles it but a 0h 0m fast looks broken/placeholder and there's no min-duration guard or 'just started' affordance. On a real surface a fast accidentally ended at start would persist as a meaningless 0h 0m row forever.","f":"Chrome judgement only: consider suppressing sub-minute completed sessions from RECENT FASTS, or render '<1m' instead of '0h 0m'. Not blocking, but the literal '0h 0m' undercuts the premium read on first open."},{"c":"typography","s":2,"i":"The 'Ready when you are' line is sansSemibold 14pt sitting directly above the window sub-label (sansRegular 12pt textTertiary). It's a redundant micro-heading that competes with the serif 'Fast when you're ready' headline above it — two stacked 'ready' phrasings, and the 14pt semibold label has more weight than the genuinely informative 12pt window line below it. Slightly muddies the editorial hierarchy.","f":"Either drop 'Ready when you are' (the headline already says it) and promote the window sub-label, or set it as a quiet Type.coach Newsreader-italic plum line per the spec's editorial-empty-state register rather than a sans semibold label. Keep the Maestro regex match by retaining the string somewhere matchable."},{"c":"style","s":2,"i":"Preset pill selected state (16:8) uses primarySoft fill + primarySolid border/text (plum outline-tint) which is correct per the §7 treatment system — but the row sits with marginTop:Spacing.xs (4) directly under the header, very tight, and the unselected pills are cream (#F6F5F2) on a white page, so they nearly disappear (same low-contrast-on-white issue as the cards). The pill row reads slightly underweight / floating.","f":"Bump presetRow marginTop 4→8 (Spacing.sm) for breathing room under the header, and give idle pills the hairline border at slightly stronger contrast (borderStrong #C9C2D6) or a faint shadow so the segmented control reads as a deliberate control on white rather than ghost pills."},{"c":"spacing","s":2,"i":"endBtn paddingVertical:16 vs landing start CTA paddingVertical:14 — two primary CTAs on the same surface with inconsistent vertical padding (16 vs 14). The design system CTA min-height is 48–52pt; 14pt vertical on the landing CTA lands a touch shy and inconsistent with the 16pt end-fast pill.","f":"Unify the two CTA vertical paddings (use 16 / Spacing.md on both) so the Start and End pills are visually identical-weight buttons; confirm resulting height ≥48pt."},{"c":"functionality","s":2,"i":"Quick-start chips show '16:8 / 18:6 / OMAD' but the user has 16:8 already selected in the preset row directly above — so the '16:8' quick-start chip duplicates the selected preset and the primary 'Start fast' CTA all does the same action. Three overlapping ways to start a 16:8 fast in one card is redundant chrome that dilutes the single-primary-action principle.","f":"Consider hiding the quick-start chip that matches the currently-selected preset, or reframe the chips as 'or jump straight in: 18:6 · OMAD' (alternatives only) so the card has one clear primary path plus genuine shortcuts, not three duplicates."},{"c":"style","s":2,"i":"Extended badge (history) uses Accent.warning amber tint (warning + '1F') + warningSolid text. Amber is locked to over-budget/alert semantics (§1.2); an 'Extended' fast is informational, not an alert. This is a minor amber-semantic bleed on the habits-adjacent surface (the habits spec §4 explicitly reserves amber for over-budget only).","f":"Recolour the Extended badge to a neutral/sage or damson info tint (e.g. Accent.info #6A4B7A soft) rather than amber, so amber stays exclusively over-budget/alert across the product."}]},{"name":"targets","model":"sonnet","impl":"apps/mobile/app/targets.tsx","gaps":[{"c":"typography","s":4,"i":"Screen title 'Daily targets' renders in sans (styles.title: fontSize 24, fontWeight 700, no fontFamily → defaults to Inter). The design system §2.2 reserves display-title (Fraunces/Newsreader) for screen H1s, and settings.md §3.5 explicitly specs the targets title in 'Fraunces 28sp bold'. This is the single most visible typographic miss on the surface — the editorial-cookbook register is broken at the very top of the screen.","f":"Set styles.title to use Type.title (Newsreader serif, 24/28) or a 28pt serif token, dropping the manual fontWeight:700. Mirror on web (Targets.tsx h1 is also sans font-bold — same fix, font-display class). Ship behind the existing Sloe/Frost flag path."},{"c":"parity","s":4,"i":"Title copy diverges: iOS says 'Daily targets', web says 'Targets'. Same surface, two different H1 strings — undocumented drift (mobile-decisions-apply-to-web rule). Web also carries a desktop breadcrumb 'Account · Targets · <date>' that mobile has no equivalent of.","f":"Pick one canonical title (spec says 'Your targets'; current shipped is 'Daily targets') and use it on both platforms. Decide whether the date-context breadcrumb is a web-only carve-out and document it, or drop it."},{"c":"parity","s":4,"i":"Goal card structure diverges hard. iOS renders buildGoalCard with a title + subtitle + status pill (on_track/stalled/wrong_way) and NO chart. Web renders a static 'Goal / Reach {weight} / Currently {weight} · could reach by ≈ {date}' card with NO status pill and NO chart. Neither platform has the weight-trend chart that settings.md §3.6 specifies as the signature trust element (two-series raw dots + trend line + dashed forecast + goal line). The two platforms show genuinely different goal information.","f":"Unify the goal card model across platforms (status pill + projected-date both, or one shared component). Then build the §3.6 weight-trend chart (it's the spec's headline differentiator vs MFP's flat line) — same chart layers both platforms, gated behind a redesign flag."},{"c":"parity","s":5,"i":"Sub-1,200 kcal safety-floor amber warning ships on web (Targets.tsx targets-safety-floor-warning) but is ABSENT on iOS targets.tsx. A mobile user who manually sets a sub-floor target gets no safety signal on the primary review surface — the platform the project treats as PRIMARY is the one missing the guardrail. settings.md §3.5 specs this warning on the targets screen.","f":"Add the same <1200 amber safety-floor card to apps/mobile/app/targets.tsx below the caption block, using the warning token + foreground ink text (amber-as-text fails contrast — keep text in #1B1814 on amber/10 fill per design-system §13)."},{"c":"style","s":4,"i":"The goal card (when present) is the weakest card on the screen — title + subtitle + a pill, no visual content, no chart, no weight context. Against the Bevel/Fitbit/Noom benchmarks in the spec it reads as a placeholder stub. In an empty test account it may not render at all (goalCard null), leaving the screen as ring + macros + help row only — thin for a 'targets' review surface.","f":"Implement the §3.6 chart inside the goal card (raw scatter + 14-day trend + dashed forecast + sage goal line + status pill top-right). Add the spec'd empty state ('Add weigh-ins to see your trend' + Scale glyph) so the card always carries weight even with no data."},{"c":"spacing","s":3,"i":"Multiple inline values sit off the 4pt grid. 'How is this calculated?' row: paddingVertical 14 and gap 12 (12 is not in the theme Spacing scale {4,8,16,20,24,32,40}). Recalculate button paddingVertical 9 and gap 6. overline marginBottom 6. kcalUnit marginLeft 6. macroTile gap 8 (sm, ok) but inline baseline-row gap 6. These read as hand-tuned one-offs rather than the consistent rhythm a premium surface needs.","f":"Snap to scale: row paddingVertical → Spacing.md (16) or 12-via-a-named-token; gaps 12/6 → Spacing.sm (8) or xs (4); button paddingVertical 9 → 8 (sm) or 12. Replace raw 6/9/14 literals with Spacing tokens throughout."},{"c":"spacing","s":3,"i":"sectionHeading ('Macros') uses marginBottom: -Spacing.xs (negative -4) to claw back the parent scroll gap (Spacing.xxl=32). Negative margins to fight the container gap is a code smell that produces a fragile, hard-to-predict gap between the heading and the macro grid, and won't match the Figma's intended heading→grid spacing.","f":"Remove the negative margin; instead wrap 'Macros' + its grid in a single section View so the scroll gap applies between sections, and set an explicit heading→grid gap (Spacing.md=16) inside that section."},{"c":"spacing","s":2,"i":"Macro tiles use width: '47%' with a 16pt grid gap. 47%+47%=94% + the gap can leave an inconsistent right-edge gutter and a centre gap that doesn't equal the screen-edge padding, so the 2x2 grid isn't on a clean column rhythm. Premium 2-up grids compute tile width from (100% - gap)/2.","f":"Replace the magic 47% with flexBasis using (100% - Spacing.md)/2, or use a flex row with gap and flex:1 tiles, so inter-tile gap and outer margins are both exactly Spacing.md and the grid is mathematically even."},{"c":"typography","s":1,"i":"Hero numeral uses Type.ringValue (48pt serif) — but the spec §3.5 calls for 40sp on the targets ring (the 48 is the Today calorie-RING hero size). Reusing the Today ring token here is intentional per the comment, but it means the targets target number is rendered at the same weight as the live progress hero, slightly overpowering the read on a static display ring. Minor, but it's a deliberate-looking deviation from the per-surface spec.","f":"Confirm with design whether 48 or 40 is canonical for the targets ring; if 40, add a Type token rather than borrowing ringValue. Low priority given it still reads well."},{"c":"style","s":3,"i":"The static display ring is a full-sweep gradient with no semantic meaning — by design (target display, not progress). But at full opacity and 10px stroke in saturated Damson it visually reads identically to a 100%-complete progress ring, which can be misread as 'you've hit your target'. settings.md §3.5 explicitly flags this false-read risk and recommends rendering the ring at reduced opacity (~0.4) to signal 'design element, not progress indicator'.","f":"Drop the display ring to ~0.4 opacity (or a lighter tint) so it reads as decorative framing, not a completed progress arc. Apply on both platforms (web ring has the same full-saturation issue)."},{"c":"functionality","s":2,"i":"The 'Edit' affordance is a small low-contrast pill (12pt sans, textSecondary/sage on card fill) in the top-right. For the primary write entry point on a read surface it's visually underweight and the sage-on-card contrast is borderline. settings.md §3.5 specs a terracotta/accent 'Edit' link.","f":"Raise Edit to accent (Accent.primarySolid) text or give it a clearer pill treatment; bump to 13–14pt label-primary. Verify contrast ≥4.5:1."},{"c":"spacing","s":2,"i":"Note the design-system doc §3.1 lists md=12/lg=16/xl=20 while the actual theme.ts Spacing scale (the source of truth the code uses) is md=16/lg=20/xl=24. The card padding (Spacing.xl=24) and macro padding (Spacing.lg=20) are correct against theme.ts but would read as 'wrong' against the doc. This is a doc/code mismatch that will keep generating phantom audit findings.","f":"Reconcile docs/ux/redesign/_design-system.md §3.1 to match the canonical theme.ts Spacing values (the prompt's scale matches theme.ts, not the doc). Not a pixel bug — a spec-hygiene gap that should be closed so future audits don't churn."},{"c":"style","s":2,"i":"Macro tiles carry the full card treatment (border + shadow + Radius.lg=16) identical to the hero card, but design-system §6.1 classes macro tiles as 'secondary/inset' cards (warm fill #F6F5F2, no shadow, optional hairline). Giving every macro tile the same elevation as the hero flattens the visual hierarchy — everything sits at one elevation level, so nothing leads.","f":"Render macro tiles as secondary cards: warm fill, no shadow, hairline only (per §6.1), reserving the elevated/bordered+shadow treatment for the hero ring and goal cards. Mirror on web."},{"c":"functionality","s":2,"i":"Empty-account read (judging chrome, not data): with no logged macros every tile shows '0 / 99 g' + '99g remaining' and a 4px min-tick bar. That's correct per the min-tick rule, but four identical '0' tiles plus a goal card that may be entirely absent makes the mid-screen read cold. There's no editorial empty-state prompt anywhere on the surface (design-system §6.3/§10.7 wants Fraunces-italic empty prompts, not bare zeros).","f":"Add a light editorial line under 'Macros' for the zero-state ('Log a meal to see today against your targets') in Fraunces italic muted, and ensure the goal card always renders (with the §3.6 empty state) so the screen never collapses to ring+zeros."},{"c":"parity","s":2,"i":"Goal-card edit entry diverges: iOS opens GoalPaceEditorSheet (or /profile) via the top 'Edit' button and the goal card itself is non-interactive; web has a 'Set a goal →' link inside the goal card only when no goal is set, and the card is otherwise non-interactive too. The interaction model for editing the goal is inconsistent between platforms.","f":"Align the goal-edit entry: either both expose an inline edit affordance on the goal card, or both route only through the header Edit. Document the chosen pattern."},{"c":"photography","s":1,"i":"No imagery is expected on this surface (settings.md §4 explicitly: 'No imagery on this surface'). Confirmed — not a gap. The only decorative element is the ring gradient. Noting for completeness so it isn't re-flagged.","f":"No action — intentionally image-free per spec. Not a gap."}]},{"name":"nutrition-sources","model":"sonnet","impl":"apps/mobile/app/nutrition-sources.tsx","gaps":[{"c":"parity","s":5,"i":"No web mirror screen exists. The SSOT data lives at src/lib/landing/nutritionSources.ts (re-exported through content.ts) but there is no rendered web 'About nutrition data' page — grep finds zero web component referencing the copy/heading. iOS users get a trust surface that web users cannot reach. This is undocumented drift, not an intentional carve-out, and violates the web/mobile-sync non-negotiable.","f":"Build the web equivalent (e.g. src/app/(marketing or settings)/nutrition-sources/page.tsx or a Settings sub-route) that maps over NUTRITION_SOURCES with the same SOURCE_DETAILS (tagline/description/url/icon via lucide-react), warm #F6F5F2 cards, hairline border, aubergine accent links, and the same intro + disclaimer copy. Ship in the same commit. Add a parity test mirroring tests/unit/settingsYourNameParity.test.ts."},{"c":"style","s":3,"i":"The 'INFO' overline is over-tracked and over-weight vs the locked eyebrow spec. It uses letterSpacing: 3 (≈0.23em at 13px) and fontWeight: '800'. The design system section-eyebrow token is Inter 10-11pt, weight 600, letter-spacing +0.08em (≈0.88 at 11px). At 13px/800/+3 it reads heavier and wider than every other eyebrow in the app, breaking cross-surface consistency.","f":"Align to the eyebrow token: fontSize 11, fontWeight '600', letterSpacing 0.88 (11 * 0.08em), colour Accent.primarySolid is acceptable but sage (textSecondary) is the canonical eyebrow colour per §2.3/§10.11. Reuse Type.eyebrow from theme.ts rather than hand-rolling."},{"c":"functionality","s":3,"i":"Back affordance is inconsistent with sibling sub-screens. nutrition-sources renders a text string '‹ Back' (literal ‹ glyph, fontSize 17/600). targets.tsx uses a lucide ChevronLeft (24pt, strokeWidth 2) and health-sync.tsx uses an Ionicons chevron-back (24pt). The text-arrow reads cheaper and is a smaller, off-standard touch target, breaking the navigation-spine consistency the design system calls for.","f":"Replace the '‹ Back' Text with the standard back control used by targets/health-sync: a lucide ChevronLeft (or Ionicons chevron-back) 24pt in colors.text, with hitSlop and a ≥44pt touch target. Keep useSafeBack('/(tabs)/settings'). This also fixes the asymmetric layout (currently a 50px right spacer hard-codes against an unknown-width text label)."},{"c":"spacing","s":2,"i":"Off-scale magic numbers break the 4pt grid (xs4/sm8/md16/lg20/xl24/xxl32/xxxl40). iconBox marginTop: 2, sourceDesc marginTop: 2, and scroll paddingBottom: 60 are all off-scale. paddingBottom 60 in particular is an arbitrary value where xxxl (40) or a safe-area-derived value belongs.","f":"Drop the marginTop: 2 nudges (the cardBody gap: Spacing.xs already provides rhythm; if the icon needs optical alignment use a flex alignItems treatment, not a 2px hack). Change scroll paddingBottom to Spacing.xxxl (40) or insets.bottom + Spacing.xxl. Audit every literal number against Spacing.*."},{"c":"typography","s":2,"i":"Screen H1 is undersized vs the settings/redesign spec. The heading uses Type.title (Newsreader serif 24pt), but the per-surface settings spec and the type ramp put a screen H1 / display-title at 28sp (Fraunces/Newsreader 28sp bold). At 24pt the H1 has less editorial presence than a Julienne-grade info screen wants, and is inconsistent with the 28sp titles specced for sibling Settings sub-screens (/targets 'Your targets' 28sp).","f":"Bump the heading to a 28sp serif token (display-subtitle/display-title range) — either Type.display (32) scaled, or add a dedicated 28pt serif title token. Keep it Newsreader serif (already correct via Type.title). Verify the font actually loads in a fresh sim capture (never assume Newsreader loaded)."},{"c":"typography","s":2,"i":"Body/intro/disclaimer sizes are slightly off the ramp and use hardcoded values instead of tokens. intro is fontSize 14/lineHeight 22 (ramp body-primary is 15/1.5; body-secondary 14/1.5 → lineHeight 21). disclaimer 12/18 is fine for caption but is hand-rolled. sourceTagline 13/600 and sourceDesc 13/20 are reasonable but all are literal numbers, not Type.* tokens — drift risk vs the locked ramp.","f":"Route intro through Type.bodyMuted (or a body-primary 15pt token), tagline through a label-primary token, description through body-secondary, disclaimer through caption. Replace all hardcoded fontSize/lineHeight with the theme Type tokens so the screen tracks the ramp automatically."},{"c":"style","s":2,"i":"Tagline and description are near-identical in weight/colour, weakening hierarchy. sourceTagline is 13/600 textSecondary and sourceDesc is 13/textSecondary — same size, same colour, only weight differs. The intended 'bold byline then long-form' rhythm reads flat because both sit in muted sage at the same size; the tagline doesn't earn its byline role.","f":"Give the tagline more lift: either render it in colors.text (ink) at 13-14/600 so it's a true byline against the muted description, or set description to textTertiary. Add a touch more separation (the marginTop: 2 → Spacing.xs) so the byline and body read as two tiers, not one block."},{"c":"functionality","s":1,"i":"Source links open via Linking.openURL with no external-link affordance consistency and no error/failure handling. The link shows a stripped URL + an Ionicons open-outline glyph, but Linking.openURL can reject (no handler) silently. Per the design system, external routes should consistently use the ExternalLink pattern; mixing Ionicons open-outline here vs lucide ExternalLink elsewhere is minor drift.","f":"Wrap Linking.openURL in a canOpenURL/catch so a failed open shows an inline sage 'Couldn't open link' rather than nothing. Standardise the trailing glyph on lucide ExternalLink (14pt, Accent.primarySolid) to match §10.1's external-link convention used across Settings rows."},{"c":"photography","s":1,"i":"Source cards use lucide line glyphs (Beaker/Utensils/Globe2/Database) in a soft-aubergine box. This is CORRECT per §0.1 (abstract/reference glyphs = line icons, not images) — flagging only to confirm it is NOT a gap and to note the cards read slightly cold/uniform because all four icon boxes share one identical primarySoft wash with no differentiation. Empty test account is fine; chrome is the judge here.","f":"No imagery change needed (§4 'No imagery on this surface' + §0.1 abstract-glyph rule both apply). Optional polish only: keep the single aubergine wash for brand consistency — do NOT tint per-source (would fight the locked single-accent rule). Leave as-is; this is a defended choice, not a gap."},{"c":"style","s":1,"i":"Top bar uses a right-side fixed 50px spacer to fake-centre the 'INFO' eyebrow against a variable-width text back button, so the eyebrow is not truly optically centred and will drift if the back label width changes. Minor but reads slightly imprecise on a premium surface.","f":"Once the back control becomes a fixed-width icon button (see back-affordance gap), set both side slots to an equal fixed width (e.g. 44pt touch targets) so the centre title is genuinely centred, or use a 3-column layout with justifyContent space-between and equal flex side containers."}]},{"name":"paywall","model":"sonnet","impl":"apps/mobile/app/paywall.tsx + apps/mobile/components/paywall/*","gaps":[{"c":"photography","s":5,"i":"The hero (apps/mobile/assets/images/paywall-hero.jpg) is a WIDE kitchen establishing shot — full range cooker, copper pans, window, marble worktop — with a comparatively small shakshuka pan. This is a real-estate/stock-kitchen register, NOT the spec's editorial finished-dish hero (_design-system.md §11.2 + paywall.md §11: 'ceramic bowls, linen napkin, shallow DoF, plated dish, @_foodstories_/@thelittleplantation, moody natural light'). The dish does not dominate the frame, the lighting is bright/even (not moody under-exposed), and the busy background competes with the food. This is the single highest-leverage gap vs Julienne — the hero is supposed to create emotional desire before any feature copy, and a kitchen-tour photo does not.","f":"Regenerate the hero asset to the §11.2 meal-photography prompt: a single plated/served finished dish in a ceramic bowl on linen/wood, tight crop so the food fills 70%+ of the frame, shallow DoF with soft bokeh background, warm moody window light, slight under-exposure. Crop portrait so the dish sits in the upper-mid third and the fade lands on negative space, not on a busy kitchen. Re-shoot both mobile (apps/mobile/assets/images/paywall-hero.jpg) and web (public/paywall/paywall-hero.jpg) from the same source for parity."},{"c":"parity","s":4,"i":"LIVE web parity bug the spec explicitly flagged as must-fix-same-commit (paywall.md §3d/§9): src/app/components/suppr/ai-paywall-dialog.tsx:67-68 still says 'Get unlimited photo logs with Pro' and 'Pro unlocks unlimited AI photo logging (100/day)'. Mobile (apps/mobile/components/AiPaywallSheet.tsx:77) correctly says 'AI photo logging up to 100 a day'. Web overstates the entitlement ('unlimited') and contradicts the honest mobile wording — a trust + parity defect.","f":"Change ai-paywall-dialog.tsx:67 title to 'Get more photo logs with Pro' and :68 body to '…Pro unlocks AI photo logging up to 100 a day — …', matching the mobile string. Copy-only, no layout impact."},{"c":"style","s":4,"i":"The 2x2 value cards read cold and sparse. Each card has a 20pt plum line-icon alone at top-left, then a big empty gap (Spacing.md=16 marginTop) to a 15pt Inter title and 13pt desc — lots of dead space top-right of every tile, and the cards are visually empty/flat against the warm fill. Against Julienne's dense, considered cards this looks under-furnished. No depth (flat 1px border, no soft elevation despite cardSoft being the DEFAULT resting treatment per theme.ts Elevation.cardSoft).","f":"In PaywallValueGrid.tsx: tighten the icon→title gap (Spacing.sm not md), and give the icon a presence — a 32–36pt plum-tint rounded chip (rgba plum 10%) behind the 18pt glyph (matches the AiPaywallSheet 60pt feature-icon pattern and Settings rows), so the tile has a focal anchor. Apply Elevation.cardSoft to lift the tiles off the page like every other Sloe card. Consider reducing desc to a single clause so the two-line wrap is consistent across all four (currently 'AI coach' wraps differently to 'Cloud sync')."},{"c":"spacing","s":3,"i":"Off-scale radius used by arithmetic across three components: PaywallValueGrid.tsx card `borderRadius: Radius.xl * 2` (=24), PaywallComparison.tsx wrap `Radius.xl * 2` (=24), PaywallPlanSelector.tsx row `Radius.xl * 2` (=24). The locked Radius ladder (theme.ts) is sm4/md6/lg8/xl12/full — there is no 24 token, and the design-system spec (§4) caps primary cards at radius-lg 16pt. 24px is the old 'consumer-wellness' roundness the 2026-05-22 radius lock explicitly tightened away from. It also makes the paywall cards inconsistent with every other Sloe card (which use Radius.lg/xl).","f":"Replace `Radius.xl * 2` with a real token — Radius.xl (12) to match standard cards, or add a documented `Radius.xxl = 16` to theme.ts and use it consistently. Never multiply a radius token inline. Pin the chosen value in designTokens test so it can't drift."},{"c":"spacing","s":3,"i":"Inconsistent inter-block gaps. Value grid uses gap Spacing.sm (8) between the four tiles but marginBottom Spacing.lg (20) below the block; comparison + plan selector each marginBottom Spacing.lg (20). The hero uses marginBottom Spacing.lg (20). But the hero's internal fade leaves a large (~70–90pt) visually empty band of white between the pan and the 'CHOOSE YOUR PLAN' eyebrow (the gradient dissolves the bottom third of a 280–380pt image into nothing), so the rhythm between hero and first content block reads much looser than every other gap. The 8pt tile gap also reads slightly tight against the 24px card radius.","f":"Reduce the hero fade dead-zone: either shorten heroHeight (the 0.44*screen clamp is generous) or move the gradient start lower (Stop offset 0.45–0.55 instead of 0.25) so the photo stays visible longer and the eyebrow sits closer to the image. Bump the 2x2 tile gap from Spacing.sm(8) to Spacing.md(16) so it matches the card-internal padding and reads less cramped at 24px radius."},{"c":"parity","s":3,"i":"Brand-eyebrow regression in the trial state. Because the capture is the trial-applies path ('Try Pro free for 7 days'), showPositioningHeadline is false, so the kicker resolves to 'CHOOSE YOUR PLAN' (paywall.tsx:735-736) — the generic neutral eyebrow — instead of 'SLOE PRO'. The most-shown paywall state (annual trial is the default and the strongest offer) therefore loses the brand mark above the headline. Julienne/the spec lead with brand presence; 'CHOOSE YOUR PLAN' is the weakest, most generic option and it's the one users see most.","f":"In paywall.tsx, make 'SLOE PRO' the eyebrow whenever a Pro offer is shown (trial OR pro-flavoured OR positioning headline), reserving 'CHOOSE YOUR PLAN' only for a true neutral non-trial generic entry — or drop the neutral variant entirely. The eyebrow is the brand beat on the highest-traffic conversion surface; it should not be generic in the default trial state."},{"c":"style","s":2,"i":"The FREE/PRO comparison PRO-column highlight is nearly invisible. PaywallComparison.tsx uses PRO_COLUMN_WASH = rgba(106,75,122,0.08) — at 8% damson on the warm card fill it reads as a barely-there grey band in the capture (the recommended-column emphasis the AllTrails/spec pattern wants is lost). The PRO header (Accent.info #6A4B7A, 11pt) is also low-contrast. The matrix reads as a plain table, not 'here is the column you want'.","f":"Lift the PRO column wash to ~12–14% damson (or add a 1px damson left/right hairline on the column) so the recommended strip is legibly distinct, and bump the PRO header weight/size or give it a small filled damson pill so it anchors the column. Verify the wash still passes 3:1 for the column boundary as a non-text element."},{"c":"typography","s":2,"i":"The hero title at trial state ('Try Pro free for 7 days') renders Newsreader 30pt/34 in plum — good — but the value-grid titles, comparison labels, and plan-selector titles are all Inter sans (correct per the data-vs-editorial rule), leaving the screen with exactly ONE serif moment (the headline) plus the serif price numeral in the plan selector (which is below the fold here). Julienne's paywall carries more editorial serif presence (section heads). The 'What the 7-day trial looks like' timeline header IS serif (Type.headline 17pt plum) per code, but the value-grid block has no section eyebrow/heading at all, so the editorial register collapses into a sans feature dump immediately after the one serif line.","f":"Add a small serif or eyebrow section header above the value grid (e.g. 'WHAT PRO ADDS' eyebrow, or a short Newsreader line) and consider a serif label on the comparison block, so the editorial voice carries past the headline rather than dropping to sans-only for the entire mid-section. Keep feature/data text Inter."},{"c":"spacing","s":2,"i":"CTA vertical padding is a raw literal: PaywallCta.tsx `paddingVertical: 16` instead of Spacing.md. The value happens to be on-scale (16) but it's hardcoded, and the spec calls for a 52pt CTA height (paywall.md §3a). With 16+16 padding plus a 16pt label the rendered height is ~50pt — close but not pinned to the spec, and the literal invites drift.","f":"Replace `paddingVertical: 16` with `Spacing.md` and add a `minHeight: 52` so the pill matches the spec's 52pt CTA height deterministically. Same for the promo Apply button (paddingVertical 12 is off-scale — should be Spacing.sm 8 or md 16) and promoInput (paddingVertical 12, off-scale)."},{"c":"functionality","s":3,"i":"Minor: the capture shows the value grid + comparison rendering on what is effectively an empty/loading-adjacent test account, and per the code the plan selector, CTA, trust row, disclosure and timeline all render BELOW the comparison matrix (off-screen in this capture). The chrome above the fold is correct and non-placeholder, but the most conversion-critical elements (price, trial CTA, 'no payment now' trust, timeline) are pushed well below two full content blocks (hero + 2x2 grid + 4-row matrix). On a real device the user must scroll past the entire matrix before seeing the price or CTA.","f":"Not a bug, but an IA concern worth validating: confirm via session replay / a scroll capture that the CTA + price are reachable without excessive scroll. Consider whether the full comparison matrix should sit BELOW the plan selector + CTA (matrix as supporting detail) rather than above it, so price + trial CTA appear sooner — the spec (§3a) places the expandable matrix below the TierCard for exactly this reason. The current order (grid → matrix → selector → CTA) buries the offer."},{"c":"style","s":2,"i":"No 'No payment due now' chip above the CTA. The spec (paywall.md §3a 'No payment now chip', benchmarked against Cal AI as 'one of the highest-converting honesty signals') calls for a success-green chip 'No payment due now — first charge on Day 7' in the trial state. The current screen relies on the subtitle ('Full Pro free for a week') and the buried disclosure to carry this; the high-converting at-the-CTA honesty chip is absent.","f":"Add the success-green 'No payment due now — first charge on Day 7' chip (rgba(94,124,90,0.08) bg, success border, Radius.full) directly above PaywallCta when trialApplies, reading from the existing trialApplies flag. No new logic."},{"c":"style","s":1,"i":"Close button is a 36x36 circle (paywall.tsx closeBtn) — below the 44x44 minimum touch target the design system (§13) and spec (§7) both mandate. It uses hitSlop={12} which mitigates the tap area, but the visible affordance is undersized vs the premium bar.","f":"Bump the close button to 44x44 (or keep 36 visual with the hitSlop, but confirm against the 44pt rule — the spec is explicit). Cheap, raises the polish floor."}]},{"name":"plan","model":"opus","impl":"apps/mobile/app/(tabs)/planner.tsx","gaps":[{"c":"functionality","s":4,"i":"Mandatory ~ tilde trust prefix is missing across the Plan surface. Meal-row kcal renders as \"145 kcal\" / \"312 kcal\" (planner.tsx ~3474, `${Math.round(meal.calories)} kcal`) and the day-total reads \"924 / 1,252 kcal\" with no tilde. The design system (§12.3) and plan spec (§7 microcopy: \"~ prefix mandatory on all estimated kcal values per trust posture\") require ~ on every estimated kcal value in Plan. Every number on this screen is an algorithm estimate, so shipping bare integers reads as false precision — the exact anti-pattern the trust posture forbids.","f":"Prefix all estimated kcal in Plan with ~: meal-row line → `~${Math.round(meal.calories)} kcal`; day-total cell (planner.tsx ~3271) → `~${total} / ${target} kcal`; verify the swap-target subtitle already uses ~ (it does) and the shopping/portion previews match. Keep tabular-nums."},{"c":"parity","s":4,"i":"Large documented web parity hole. MealPlanner.tsx:134-146 explicitly cuts per-day P/C/F pills, day-total kcal, the portion stepper, Move-meal, leftover rows, templates, and per-day macro breakdown from web. So the entire macro-accounting layer the user sees on iOS (the 4 macro cells + amber day total + portion pills + Estimated·verify) simply does not exist on /plan. This is far past acceptable structural divergence — a user on web cannot see whether a day hits its macros at all.","f":"Restore per-day macro breakdown + day-total kcal + portion display on web as the plan spec §5 recommends (ties to ENG-699 move-meal gap). At minimum surface the day macro deltas and the ~kcal day total in each of the 7 web day columns so the algorithmic-fit signal is present on both platforms. File/track against the existing web-restore ticket."},{"c":"functionality","s":3,"i":"Generate CTA reads \"Generate ▾\" (a dropdown affordance), not the state-aware \"Build plan\" (first generate, sparkles icon) / \"Regenerate\" (refresh icon) the spec §3.6 + microcopy table specify. With a plan already present the primary button should say Regenerate; \"Generate ▾\" is ambiguous (generate what? a new one? from where?) and the ▾ glyph is a low-craft disclosure marker on the hero action.","f":"Make the summary primary button state-aware: no plan → \"Build plan\" + Sparkles icon; plan exists → \"Regenerate\" + RefreshCw icon. Move the source-picker (library/discovery) into the disclosed menu rather than hanging a ▾ off the label. Mirror on web."},{"c":"style","s":4,"i":"Per-day macro accounting is a flat 4-cell grid (PlanDayMacroSummary: cream slabs, \"P 93g / On track\" or \"-50g\"), not the spec'd MacroFactor-style range-band tracks (§3.2 / §7.5). The current cells make the band threshold invisible — a user sees \"-50g\" on carbs with no sense of whether that is inside or outside the acceptable band. It is functional but reads as a generic tracker stat strip, not the engineered-plan confidence artefact that is Suppr's differentiator. The check + \"On track\" on cell 1 sitting beside three bare \"-Ng\" cells also creates inconsistent treatment within one row.","f":"Implement the band-track row from §7.5: full-width rail (#ECEAE4, 4pt), shaded acceptable band (#F6F5F2 + 1pt border), 8pt macro-coloured value dot, 1pt target tick, amber rail tint when out-of-band. Collapsed-by-default with a chevron, auto-expand day 1. This is the single highest-leverage upgrade to make the surface read as premium-engineered rather than a stat grid."},{"c":"spacing","s":3,"i":"Multiple off-scale paddings. The locked Spacing scale in constants/theme.ts is xs:4 sm:8 md:16 lg:20 xl:24 (NO 12 token; md is 16). The planner hardcodes 12/14/10 repeatedly: filterChip paddingHorizontal:12 paddingVertical:8 (12 is off-scale); mealRow paddingHorizontal:14 paddingVertical:8 (14 off-scale); addSlotBar/planDayCardMeta paddingHorizontal:12/14; PlanDayMacroSummary cell paddingHorizontal:4 (sub-xs). The capture shows the macro cells and meal rows reading slightly tight/uneven against the cream summary slab above them.","f":"Snap all to the scale: filterChip → ph:Spacing.md(16)/pv:Spacing.sm(8) or ph:12 only if a deliberate sub-md token is added; mealRow ph → Spacing.md (16) to align the row content edge with the summary card and day header (currently 14 vs 16 elsewhere causes a 2px misalignment); macro cell ph → Spacing.xs (4 is fine) but unify the row gap. Audit every literal 10/12/14 in the StyleSheet and replace with tokens."},{"c":"typography","s":2,"i":"Day name (\"Tue\") uses Type.headline → Newsreader serif at 18pt, which is correct, but the weekday label in the capture reads as a short abbreviation (\"Tue\") rather than the fuller editorial day name the spec wants (\"Tuesday  28 May\" with serif day name + Inter muted date). Right now the day header is just \"Tue  TODAY\" + amber kcal — no date, so the editorial register the spec §3.2 calls for (Fraunces day name + Inter 12pt date) is half-built. The \"TODAY\" pill is Inter 10pt all-caps tertiary which is fine.","f":"Render the full weekday name in serif plus the calendar date in Inter muted (e.g. \"Tuesday\" Newsreader 18 + \"9 Jun\" Inter 12 textTertiary) to match §3.2 and lift the per-day header from a terse abbreviation to the editorial day header the spec specifies."},{"c":"style","s":3,"i":"The macro-cell delta uses amber \"-50g / -14g / -22g\" for UNDER-target macros. Per the algorithm's cutting bias (spec §7.7: \"Under-target day: no colour change — being under is not a problem\") and the calm-coach voice, flagging under-protein/carbs/fibre in alert-amber on a fresh empty-ish plan reads as three warnings stacked, which is alarming rather than calm. Amber should signal over-budget; under should be neutral muted.","f":"In PlanDayMacroSummary, branch the gap colour on sign: roundedDiff > 0 (over) → Accent.warning amber; roundedDiff < 0 (under) → colors.textTertiary neutral. Keep the residual-protein hint as the single intentional under-protein alert. This stops a normal under-target day reading as failure."},{"c":"photography","s":3,"i":"Meal-row thumbnails are only 36x36pt (mealIconBox). The plan spec §3.3 calls for 56x56pt hyperreal editorial dish photography to \"make the plan feel real and appetising before the user has cooked anything — the primary emotional job of a planner.\" At 36px the FLUX dish photos (which DO render correctly in the capture — good) are too small to read as appetising food; they read as favicons. The editorial-luxury bar (Julienne) leads with large, lush dish imagery.","f":"Increase meal-row thumbnail to 56x56pt with 8pt radius per §3.3 and 3.3 card anatomy; bump row min-height toward the spec's 72pt to give the photo room. Verify the RecipeHeroFallback sage→cream tile scales cleanly at 56px."},{"c":"functionality","s":2,"i":"No inline swap affordance on meal rows — the capture shows only a \"...\" overflow per row. Swap is the primary planner verb and the spec §3.3 wants it as a one-tap inline ⇄ glyph (terracotta/plum). Currently swap is buried 1 tap into the rowMenu action sheet. The row's whole surface opens the action sheet (tap == long-press == overflow all route to rowMenu), so there is no direct tap-to-open-recipe either, which is a slightly surprising interaction model.","f":"Add the inline ⇄ (lucide arrow-left-right) affordance to each meal row top-right per §3.3, wired directly to swapMeal with the existing over-target confirm. Reconsider making row tap open the recipe detail (spec §3.3 \"Tap row → opens recipe detail\") with overflow/long-press for the menu, so tap is not overloaded onto the action sheet."},{"c":"style","s":3,"i":"The week-overview summary card has no visual encoding of which days hit vs fell short — it is the editorial headline + prose subtitle only. The spec §3.1 calls for a weekday dot row (sage/amber/hollow per day) and a 7-day stacked-macro bar strip as the trust/confidence artefact (\"communicates this plan was engineered — a signal unique to Suppr\"). Without them the slab is just two text lines on cream and the \"engineered plan\" differentiator is invisible at first glance.","f":"Add Layer 2 (7 weekday dots, tappable-to-scroll) and Layer 3 (7-bar stacked macro strip) to the summary card per §3.1. Both are zero-new-data (derived from summaryScore + per-day totals already computed). This converts the slab from a sentence into the at-a-glance week-quality visual the surface is built around."},{"c":"style","s":2,"i":"CTA treatment inconsistency on the summary card. \"Generate ▾\" is a plum OUTLINE (transparent fill, 1.5px primarySolid border) and \"Adjust constraints\" is a neutral hairline outline — two near-identical outline pills side by side give the primary action no visual priority. The design system (§10.9 / treatment system) rations the filled aubergine to conversion-critical CTAs, which is correct, but two equal-weight outlines flatten the action hierarchy so neither reads as primary.","f":"Differentiate: keep the plum outline on the primary (Generate/Build) but make the secondary a quieter ghost text-link or drop its border weight, so the eye lands on the generate action first. Confirm against the sloe-component-treatments.html primary-vs-secondary spec."},{"c":"spacing","s":2,"i":"Macro cell row gap is Spacing.xs (4pt) between four cells and the cells use 4pt horizontal padding — at narrow widths this packs \"P 93g / On track\", \"C 70g / -50g\" etc. tightly, and in the capture the four cells read slightly cramped relative to the generous summary slab above. The two-line cell content (value + status) at 13/10pt in a 4pt-padded slab is dense.","f":"Increase inter-cell gap to Spacing.sm (8) and cell vertical padding to Spacing.sm, and confirm the value/status line gap (currently 3) sits on-scale (use 4/xs). Re-shoot to confirm the row breathes against the day header."},{"c":"functionality","s":3,"i":"Silent save failure persists (planner.tsx persistPlan ~993-1001): save_meal_plan errors only console.warn in __DEV__ and are silent in production. A user who regenerates/swaps on poor connectivity loses the change with zero feedback. Flagged in the spec §2.9 / §9 as a correctness gap that must be ticketed, not left silent (violates the no-silent-deferrals rule).","f":"Surface a non-blocking toast on save failure (\"Changes couldn't be saved — check your connection\") reusing the regenerate-toast host pattern, and ensure a Linear ticket ID is referenced in the code comment rather than a bare console.warn."},{"c":"typography","s":1,"i":"Summary headline numerals \"0 of 7 days\" are not differentiated from the surrounding serif words. Spec §3.1 wants the count (\"5 of 7\") rendered as an emphasised display numeral in the accent (plum) — warm, not alarming — so the eye lands on the score. Currently the whole headline is one uniform Newsreader run (and at 0/7 with win flag it tints sage textSecondary, fine), but the score itself gets no typographic emphasis at the common non-7/7 states.","f":"Split the headline so the \"{hits} of {total}\" fragment renders at a heavier serif weight / accent colour (plum) per §3.1, while the lead-in stays ink. Keep the win-moment tone logic on top."},{"c":"functionality","s":1,"i":"Portion pill (\"0.5× portion\") has no visible tappable affordance and, per the row interaction model, tapping the row opens the action sheet rather than the portion modal directly. Spec §3.3 wants the portion pill to carry a visible underline/affordance signalling it opens the portion modal on tap. As shipped the pill looks like a static label.","f":"Give the portion pill a tap affordance (subtle underline or chevron) and wire a direct tap to portionModal, per §3.3, so re-portioning is one tap rather than row→action-sheet→Change portion size."}]},{"name":"settings","model":"sonnet","impl":"apps/mobile/components/settings/SettingsBundleContent.tsx","gaps":[{"c":"typography","s":4,"i":"The profile name renders as the lowercase email handle 'gracemturner' (avatarInitial/displayName fall back to session.user.email.split('@')[0] — SettingsBundleContent.tsx L1485-1495). In the serif 24sp display face this looks like a username string, not an editorial identity header. The spec (§3.2, token table) reserves Fraunces 20-24sp for the user's NAME as the surface's one editorial moment; a lowercase handle squanders it and undercuts the premium first impression.","f":"Source the display name from user_metadata.full_name (the same value the 'Your name' field writes and Today greets from) via firstNameFromMetadata / profileDisplayName, falling back to a Title-Cased handle only as a last resort. Title-case any handle fallback so it never renders all-lowercase in the serif face."},{"c":"style","s":4,"i":"The stats strip on an empty account is a single full-width tile ('8 / Recipes') with a thin macro-tinted border (borderColor: c + '55', L1661) — it reads as a lone, cold, half-empty chip rather than the two-tile progress signal the spec wants. Stretched full-width with the streak tile hidden at 0, it looks like leftover chrome, not a designed moment. Spec §3.2 calls for two equal side-by-side tiles (Recipes + Streak with a 7-dot weekday row) on white cards with hairline borders.","f":"When only one stat is non-zero, either render it left-aligned at tile width (not stretched full-width) or fold the single value into the profile row as a subtitle. When both show, render the spec's two equal tiles. Drop the macro-colour-tinted border (the '+55' alpha clay/sage ring is the only macro colour on this control surface — off-system per §1.3 'macro colours belong to nutrition data only'); use the standard hairline #ECEAE4 border instead."},{"c":"spacing","s":3,"i":"Every SettingsRow / SegmentedRow / Display toggle uses hardcoded paddingVertical: 12 + paddingHorizontal: 14 (L424-425, L307-308, L2117-2118, etc.). Neither 12 nor 14 is on the Spacing scale (xs4/sm8/md16/lg20/xl24); 14 in particular is an arbitrary off-grid value repeated ~10×. The design-system doc §3.2 specifies standard card padding of 16 all sides. The rows read slightly tight and the horizontal inset doesn't align with the 16pt screen-edge margin.","f":"Replace the literal 12/14 with Spacing tokens: paddingHorizontal: Spacing.md (16) and paddingVertical: Spacing.md (16) for standard rows, or Spacing.sm (8)→Spacing.md (16) if a denser rhythm is wanted — but pick scale values. Audit the whole bundle for stray 12/14/18 literals and route them through Spacing."},{"c":"typography","s":3,"i":"The stat tile numeral is sans Inter 18px/700 (L1664) and the 'Your name' field label is sans 13px/700. Spec §2.2 + the settings token table require Fraunces/Newsreader for stat-tile numerals (24sp) — 'any number that is the primary focus of a card uses the serif display face'. A sans 18px number in a tile that is meant to be a progress signal misses the editorial ramp and reads as a generic tracker stat.","f":"Set the stat-tile value to FontFamily.serifSemibold at ~24sp (recipes = clay/aubergine accent, streak = ink per token table). Keep the small caption ('Recipes') in Inter. The numeral is the focal point of the tile and earns the serif."},{"c":"parity","s":3,"i":"Mobile Settings has NO Units / measurement-system control (zero matches for measurement_system in SettingsBundleContent.tsx), while web Settings.tsx (L979-998) ships a full Metric/Imperial segmented control writing profiles.measurement_system. This is the documented P1 functional+parity gap in settings.md §3.8 #1 — every body-stat and nutrition input on mobile is metric-only. Still open.","f":"Add a 'Units' SegmentedRow (Metric / Imperial) to the Display card on mobile, writing profiles.measurement_system via savePref, with the same option labels as web ('Metric (g, kg, ml)' / 'Imperial (oz, lb, cups)'). Place it as the first row of Display per spec §3.8. Pin placement parity with a unit test like settingsYourNameParity.test.ts."},{"c":"parity","s":3,"i":"Section-heading treatment diverges sharply: mobile uses ALL-CAPS sans eyebrows (SectionHeading: Inter 11px +0.9 tracking, L188-206), web uses serif card headings ('font-[family-name:var(--font-headline)] text-xl font-medium', e.g. L876 'Personal', L979 'Preferences'). These are two different visual systems for the same grouping concept. The design-system doc §2.2 prescribes ALL-CAPS Inter eyebrows for section labels (PROFILE/MEMBERSHIP/etc.), so MOBILE is correct and WEB is off-system — but they must not stay divergent.","f":"Bring web section headings to the same ALL-CAPS Inter eyebrow treatment (10-11px, +0.08em tracking, sage) per design-system §2.2, reserving the serif headline face for the screen title only. Update web Settings.tsx section <h3> elements to the eyebrow style; keep DANGER ZONE amber."},{"c":"functionality","s":3,"i":"The Notifications row still routes to the read-only inbox ('/(tabs)/notifications', L2363) and shows only 'Daily reminder at {time}' or 'Off' — there is no reminder-time editor or per-kind toggles on mobile. Web has per-kind notification toggles (Settings.tsx L1445+). settings.md §3.9 flags this as a genuine functional gap (users cannot change their daily reminder time on mobile after onboarding) and a parity gap (per-kind toggles web-only). The row chrome looks complete but the destination is the wrong surface.","f":"Build NotificationPrefsSheet (per spec §3.9): a Daily-reminder toggle + inline time picker (writes notification_prefs.reminder_time) and per-kind toggles (mealReminders, weeklyReport, newRecipes, etc.) mirroring web, with a 'View notification inbox →' link at the bottom. Route the Notifications row to this sheet, not the inbox."},{"c":"spacing","s":2,"i":"Vertical rhythm between the profile row, the Sloe Pro banner, and the stats strip uses off-scale ad-hoc margins: profile row marginTop 4 (L1521), Sloe Pro banner marginTop 18 (L1602), stats strip marginTop 10 (L1639). 18 and 10 are not on the Spacing scale (should be xl24/lg20 and sm8/md16). The banner sits a touch close to the stat tile and the spacing reads slightly improvised rather than composed.","f":"Snap these to scale: banner marginTop → Spacing.lg (20) or Spacing.xl (24); stats strip marginTop → Spacing.sm (8) or Spacing.md (16). Establish one consistent inter-block gap (Spacing.xl between the identity cluster and the first section eyebrow already uses SectionHeading marginTop 24 — good; match the cluster spacing to it)."},{"c":"style","s":2,"i":"The 'Sloe Pro' banner is correct and on-brand (Accent.primarySoft tint, outline Manage pill) but carries no value articulation — it's just a wordmark + Manage button. For a FREE user (the captured account shows 'Pro plan', but the free path renders the same banner shell + a separate 'Upgrade your plan' row below) the at-a-glance banner says nothing about what Pro is. Oura's pattern (spec §3.3) dignifies the tier with an inline status/value line. As rendered it's a slightly empty premium bar.","f":"For Pro users, add a small status subtitle under 'Sloe Pro' (e.g. 'Active · manage anytime') so the banner reads as a daily micro-reward, not a bare label. For free users, surface one value phrase ('Unlimited recipes · AI logging') in the banner rather than only in the row below, so the banner isn't a content-free shell."},{"c":"style","s":2,"i":"The Membership card's leading glyphs use a colour-tinted rounded SQUARE (width36/height36, borderRadius 12, backgroundColor accent.primary + '22'/'18', L1790-1800 & L1850-1860) — a DIFFERENT container shape from every other row in the bundle, which uses the IconBox white circle + hairline (treatment per Figma 335:2). Within one screen there are two icon-container languages (tinted square in Membership, white circle everywhere else), which breaks the consistency a premium surface needs.","f":"Replace the bespoke tinted-square icon containers in the Membership upgrade and Manage-subscription rows with the shared IconBox (white circle + hairline), passing accent.primary as the glyph colour. One icon-container treatment across the whole surface."},{"c":"typography","s":2,"i":"Row primary labels are Inter 13px/600 (SettingsRow L436-441) where the design-system token table for this surface specifies row primary label = Inter 15sp (§10.1, settings token table 'Row primary label — Inter 15sp'). 13px labels read slightly small/dense for a low-frequency, high-trust control surface and sit below the 15pt body-primary ramp.","f":"Bump SettingsRow label to 15sp (lineHeight ~20) and the subtitle to 13sp per the token table, so the row type matches the documented ramp and the 44pt touch target reads comfortably."},{"c":"functionality","s":1,"i":"The 'Recipes' section contains a single 'Create recipe' row (L2380-2391) sitting as its own eyebrow + card. One row under its own ALL-CAPS section eyebrow reads as over-structured / sparse — a lone card the size of a section. On a premium surface a one-item section looks like an unfinished group.","f":"Either fold 'Create recipe' into an adjacent group (e.g. under a broader 'Library' or 'Account' section) or, if it must stand alone, drop the section eyebrow so it doesn't advertise an empty-feeling group. Avoid one-row sections behind their own eyebrow."},{"c":"spacing","s":1,"i":"SegmentedRow inner gap is 10 and the segmented rail uses borderRadius 8 with padding 2 (L307-349) — the 10 gap is off-scale (should be sm8 or md16) and is inconsistent with the 12 gap used in SettingsRow (L423), so the Display card's segmented controls have a marginally different internal rhythm from the toggle rows above them.","f":"Normalise the SegmentedRow vertical gap to a scale value (Spacing.sm 8 or Spacing.md 16) and match the icon↔label gap to the SettingsRow value (12 → Spacing.md 16) so toggle rows and segmented rows share one internal rhythm."}]}]

const HARD_RULES = [
  'TOKENS ONLY: use the EXISTING design tokens. Mobile: import { Type, FontFamily, Spacing, Radius, Elevation, Accent, MacroColors } from "@/constants/theme" (or the correct relative path). Web: use the CSS custom properties / existing utility classes. NEVER edit apps/mobile/constants/theme.ts or src/styles/theme.css — those are LOCKED and shared.',
  'SERIF IS A TOKEN, NOT A STRING: to make text serif, use Type.title / Type.headline / Type.display / Type.heroValue / Type.ringValue, or FontFamily.serifRegular/serifMedium/serifSemibold — these are wired to the already-loaded Newsreader/Fraunces faces. NEVER hardcode a new fontFamily string or rely on a system-serif fallback. Recipe names + meal names + screen H1s + the single biggest numeral on a screen MUST be serif (design-system §2.3).',
  'SPACING ON-SCALE: every gap/padding must be one of Spacing.xs(4) sm(8) md(16) lg(20) xl(24) xxl(32) xxxl(40). Radius must be Radius.sm(4)/md(6)/lg(8)/xl(12)/full. Replace any off-scale literal (12,14,10,6,18,24px) with the nearest correct token, matched to the Figma rhythm. Do NOT eyeball — pick the token deliberately. Cards must not crowd (too tight) or float (too loose).',
  'WEB + MOBILE LOCKSTEP: after fixing the mobile file, Glob/Grep for the web mirror of this surface (search app/** and src/**) and apply the equivalent fix so the surfaces stay in parity. If no web mirror exists and the audit fix says to build one, build it following the audit fix exactly; if that is more than ~80 lines or genuinely blocked, DEFER it (gapsDeferred with linearNeeded:true and a precise reason) rather than half-build it.',
  'ELEVATION: where the audit says a card blends into the background, spread Elevation.cardSoft on an OUTER wrapper (RN overflow:hidden clips iOS shadows) — do not invent a new shadow.',
  'FLAG-GATE NET-NEW STRUCTURE: if a gap adds a brand-new visual block/section (e.g. a profile identity card), gate the new path behind the EXISTING flag the audit names (e.g. settings_redesign_v2) via isFeatureEnabled, leaving the old path in the else. Pure token swaps (serif, on-scale spacing) and bug fixes do NOT need a flag.',
  'NO GUESSING ON PRODUCT CALLS: if a gap needs a product/structural decision (e.g. weight-tracker redirect-vs-port, or removing a whole flow), do the safe in-file improvement (e.g. serif + spacing) and DEFER the structural decision (gapsDeferred, linearNeeded:true) — do not unilaterally delete or re-route a screen.',
  'STAY IN YOUR FILES: edit only this surface\'s own files + its web mirror. Do NOT edit another surface\'s screen, and do NOT add helpers to shared utils. If a fix needs a shared-file change, defer it.',
  'DO NOT run tsc / next build / full test suites (CPU starvation — the orchestrator runs them centrally afterward). You MAY Read/Grep/Glob freely and run a quick targeted grep to confirm a token name.',
  'NUTRITION SAFETY: never change nutrition numbers, matching logic, or targets math. These are visual/parity fixes only.',
]

const SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['surface','filesChanged','gapsFixed','gapsDeferred','parityNote','summary'],
  properties: {
    surface: { type: 'string' },
    filesChanged: { type: 'array', items: { type: 'string' }, description: 'every file path edited or created' },
    gapsFixed: { type: 'array', items: { type: 'object', additionalProperties:false, required:['issue','what'], properties: { issue:{type:'string'}, what:{type:'string',description:'concretely what you changed'} } } },
    gapsDeferred: { type: 'array', items: { type: 'object', additionalProperties:false, required:['issue','reason','linearNeeded'], properties: { issue:{type:'string'}, reason:{type:'string'}, linearNeeded:{type:'boolean'} } } },
    parityNote: { type: 'string', description: 'what you did to keep web+mobile in sync, or why no web change was needed' },
    summary: { type: 'string', description: 'one-line summary of the surface after your fixes' },
  },
}

phase('Fix')

const results = await parallel(SURFACES.map((s) => () =>
  agent(
    [
      'You are a senior product engineer fixing ONE iOS surface of "Sloe" (luxury recipe + nutrition app) to PREMIUM PARITY (editorial-luxury equal-or-better than Julienne). You implement real, correct code — not mockups.',
      '',
      'SURFACE: ' + s.name,
      'IMPLEMENTATION FILE(S): ' + s.impl,
      '',
      'READ FIRST: the impl file(s) above; the locked design system at docs/ux/redesign/_design-system.md (for the exact Type/Spacing/Radius token names + the serif rules §2.3); and Grep apps/mobile/constants/theme.ts for the exact token export names before using them.',
      '',
      'FIX THIS SURFACE\'S GAP LIST (highest severity first). For each, apply the concrete fix:',
      ...s.gaps.sort((a,b)=>b.s-a.s).map((g,idx)=> (idx+1)+'. [sev '+g.s+' · '+g.c+'] ISSUE: '+g.i+'  >> FIX: '+g.f),
      '',
      'HARD RULES (non-negotiable):',
      ...HARD_RULES.map((r,i)=>(i+1)+'. '+r),
      '',
      'When done, return the structured changelist. Be honest: list what you actually changed in gapsFixed, and anything you could not safely complete in gapsDeferred (with linearNeeded + a precise reason). Do not claim a gap fixed unless you edited code for it.',
    ].join('\n'),
    { label: 'fix:' + s.name, phase: 'Fix', model: s.model, agentType: 'executor', schema: SCHEMA },
  ).then((v) => (v ? { ...v, surface: s.name } : { surface: s.name, error: true })),
))

const clean = results.filter((r)=>r && !r.error)
const failed = results.filter((r)=>!r || r.error)
const totalFixed = clean.reduce((n,r)=> n + (r.gapsFixed||[]).length, 0)
const totalDeferred = clean.reduce((n,r)=> n + (r.gapsDeferred||[]).length, 0)
const linearNeeded = clean.flatMap((r)=> (r.gapsDeferred||[]).filter(g=>g.linearNeeded).map(g=>({surface:r.surface, ...g})))
const allFiles = [...new Set(clean.flatMap((r)=> r.filesChanged||[]))]

log('Fixed '+clean.length+'/'+SURFACES.length+' surfaces — '+totalFixed+' gaps fixed, '+totalDeferred+' deferred, '+allFiles.length+' files touched, '+linearNeeded.length+' need Linear tickets'+(failed.length?(' — FAILED: '+failed.map(f=>f.surface).join(',')):''))

return { perSurface: clean, failed: failed.map(f=>f.surface), totalFixed, totalDeferred, linearNeeded, allFiles }
